/*
 * OCR B A-Level Biology — Exam Practice Question Bank
 * All written/exam-style questions with OCR command words and mark schemes.
 * B1: 40 questions, B2–B6: 50 questions each, varying from 1-mark to 8-mark questions.
 */

const BIOLOGY_OCR_B_PRACTICE = {

  /* ─────────────────────────────────────────────────────────── B1 */
  'B1': {
    name: 'Development of Practical Skills',
    questions: [
      { q: 'State what is meant by the independent variable in an experiment.', marks: 1, markScheme: `• The variable that is deliberately changed/manipulated by the experimenter (1)` },
      { q: 'State what is meant by the dependent variable.', marks: 1, markScheme: `• The variable that is measured as the outcome of the experiment (1)` },
      { q: 'State what is meant by a control variable.', marks: 1, markScheme: `• A variable kept constant to ensure a fair test / prevent it from affecting the dependent variable (1)` },
      { q: 'State the difference between accuracy and precision.', marks: 2, markScheme: `• Accuracy is how close a measured value is to the true value (1)\n• Precision is how close repeated measurements are to each other (1)` },
      { q: 'State what is meant by the resolution of a measuring instrument.', marks: 1, markScheme: `• The smallest change in a quantity that the instrument can detect / the smallest scale division (1)` },
      { q: 'State one way to reduce random error in an experiment.', marks: 1, markScheme: `• Take repeat measurements and calculate a mean (1)` },
      { q: 'State one way to reduce systematic error.', marks: 1, markScheme: `• Calibrate the instrument correctly / use a different measurement technique to cross-check / zero the instrument before use (1)` },
      { q: 'Describe how to prepare a serial dilution with a dilution factor of 10, starting from a 1 mol/dm³ solution.', marks: 3, markScheme: `• Take 1 cm³ of the stock solution and add to 9 cm³ of distilled water — this gives 0.1 mol/dm³ (1)\n• Mix thoroughly (1)\n• Repeat: take 1 cm³ of the new dilution and add to 9 cm³ of distilled water to get 0.01 mol/dm³, and so on (1)` },
      { q: 'Explain why a water bath is used rather than a Bunsen burner in enzyme experiments.', marks: 2, markScheme: `• A water bath provides a uniform/constant temperature throughout the solution (1)\n• A Bunsen burner heats unevenly and is difficult to control precisely (1)` },
      { q: 'Explain the purpose of a control experiment.', marks: 2, markScheme: `• Provides a baseline for comparison to show that observed changes are due to the independent variable (1)\n• All conditions are identical except the independent variable is absent or at a standard level (1)` },
      { q: 'A student measures the volume of gas produced. The uncertainty of the gas syringe is ±0.5 cm³. The volume measured is 20 cm³. Calculate the percentage uncertainty.', marks: 2, markScheme: `• Percentage uncertainty = (0.5 / 20) × 100 (1)\n• = 2.5% (1)` },
      { q: 'Explain why repeating an experiment improves reliability.', marks: 2, markScheme: `• Repeating allows identification and exclusion of anomalous results (1)\n• A mean of repeats reduces the impact of random variation, giving a more representative value (1)` },
      { q: 'Describe how to calibrate an eyepiece graticule using a stage micrometer.', marks: 3, markScheme: `• Place the stage micrometer on the microscope stage and focus (1)\n• Align the eyepiece graticule scale with the stage micrometer scale (1)\n• Count how many graticule divisions correspond to a known distance on the stage micrometer to calculate the value of one graticule division (1)` },
      { q: 'A student obtains the results: 5.2, 5.1, 5.3, 8.7, 5.2. Identify the anomalous result and calculate the mean excluding it.', marks: 2, markScheme: `• Anomalous result: 8.7 (1)\n• Mean = (5.2 + 5.1 + 5.3 + 5.2) / 4 = 20.8 / 4 = 5.2 (1)` },
      { q: 'State when it is appropriate to use a bar chart rather than a line graph.', marks: 1, markScheme: `• A bar chart is used when the independent variable is categoric/discontinuous (1)` },
      { q: 'Explain why a line of best fit is drawn on a scatter graph rather than joining all points.', marks: 2, markScheme: `• A line of best fit shows the general trend/pattern in the data (1)\n• It reduces the effect of random errors and anomalies on the interpretation of the relationship (1)` },
      { q: 'Describe how a colorimeter can be used to measure the concentration of a coloured solution.', marks: 3, markScheme: `• Set the colorimeter to the appropriate wavelength (complementary colour absorbed by the solution) (1)\n• Calibrate/zero with a blank (distilled water or unreacted solution) (1)\n• Measure the absorbance of the sample — higher absorbance = higher concentration; use a calibration curve to determine unknown concentrations (1)` },
      { q: 'State what is meant by the term "validity" in an experiment.', marks: 2, markScheme: `• An experiment is valid if it measures what it claims to measure (1)\n• Control variables must be controlled so the results are due to the independent variable only (1)` },
      { q: 'Explain why large sample sizes improve the validity of ecological surveys.', marks: 2, markScheme: `• A larger sample is more representative of the whole population/habitat (1)\n• It reduces the effect of natural variation and chance, increasing confidence that results reflect the true situation (1)` },
      { q: 'Describe how to use a potometer to measure the rate of water uptake by a plant shoot.', marks: 3, markScheme: `• Cut the shoot under water and assemble the potometer with no air bubbles (1)\n• Allow an air bubble to enter the capillary tube and measure the distance it moves over a set time (1)\n• The rate of water uptake = distance moved by bubble / time (1)` },
      { q: 'Explain the difference between a null hypothesis and an alternative hypothesis.', marks: 2, markScheme: `• Null hypothesis: there is no significant difference/correlation between variables — any difference is due to chance (1)\n• Alternative hypothesis: there is a significant difference/correlation that is not due to chance (1)` },
      { q: 'A chi-squared test gives χ² = 5.2 with 2 degrees of freedom. The critical value at p=0.05 is 5.99. State the conclusion.', marks: 2, markScheme: `• χ² (5.2) is less than the critical value (5.99) (1)\n• Therefore we accept the null hypothesis — there is no significant difference between observed and expected values (1)` },
      { q: 'Explain why a student should use a pipette rather than a measuring cylinder to measure 5 cm³ of enzyme solution.', marks: 2, markScheme: `• A pipette has a smaller uncertainty/higher resolution than a measuring cylinder for that volume (1)\n• This reduces percentage error and increases the accuracy of the measurement (1)` },
      { q: 'Describe how to carry out a risk assessment for an experiment using hydrogen peroxide.', marks: 2, markScheme: `• Identify hazard: hydrogen peroxide is an irritant/oxidiser at higher concentrations (1)\n• Control measure: wear safety goggles and gloves; use dilute concentrations; wipe up spills immediately (1)` },
      { q: 'Evaluate the use of subjective colour change (e.g., Benedict\'s test by eye) vs using a colorimeter.', marks: 3, markScheme: `• Subjective assessment varies between observers / introduces human bias / is qualitative only (1)\n• A colorimeter provides objective, quantitative, reproducible measurements of absorbance (1)\n• Evaluation: colorimeter is more reliable and allows statistical analysis, but requires more equipment and a calibration curve (1)` },
      { q: 'Explain why biological samples must be stained before viewing under a light microscope.', marks: 2, markScheme: `• Most biological structures are transparent/colourless, making them difficult to see (1)\n• Stains bind to specific molecules (e.g., methylene blue to DNA), increasing contrast so structures become visible (1)` },
      { q: 'Describe how to use a haemocytometer to estimate cell concentration.', marks: 3, markScheme: `• Load the cell suspension into the haemocytometer chamber using a pipette (1)\n• Count the number of cells in a known number of grid squares under the microscope — use a consistent rule for cells touching gridlines (1)\n• Calculate concentration: cells counted / (number of squares × volume per square × dilution factor) (1)` },
      { q: 'A student measures the rate of photosynthesis at five light intensities, with three repeats at each. Explain why standard deviation is a useful measure for these data.', marks: 2, markScheme: `• Standard deviation indicates the spread/variability of the data around the mean (1)\n• A small SD shows the results are consistent/reliable; a large SD indicates high variability and less confidence in the mean (1)` },
      { q: 'Explain the difference between a Type 1 and a Type 2 error in statistical testing.', marks: 2, markScheme: `• Type 1 error: rejecting the null hypothesis when it is true (false positive) (1)\n• Type 2 error: accepting the null hypothesis when it is false (false negative) (1)` },
      { q: 'Describe how a student should use a quadrat and random number generator to estimate population density.', marks: 3, markScheme: `• Use a random number generator to produce coordinates within the sampling area (1)\n• Place the quadrat at each pair of coordinates and count/record the organisms present (1)\n• Calculate mean number per quadrat and scale up: density = mean count / quadrat area (1)` },
      { q: 'Explain why a buffer solution is used during cell fractionation.', marks: 2, markScheme: `• A buffer maintains a constant pH (1)\n• This prevents enzymes from denaturing due to pH changes, keeping organelles intact and functional (1)` },
      { q: 'Describe how a student could use a respirometer to measure the rate of aerobic respiration in germinating seeds.', marks: 4, markScheme: `• Place germinating seeds in one tube and dead seeds/glass beads (control) in another, both with a soda-lime/KOH CO₂ absorber (1)\n• Seal the apparatus and allow to equilibrate at a constant temperature in a water bath (1)\n• As O₂ is consumed and CO₂ absorbed, pressure drops — a coloured liquid in the manometer/capillary tube moves toward the seeds (1)\n• Rate of respiration = distance moved by liquid / time (1)` },
      { q: 'Explain why an isotonic solution is used when preparing tissue for cell fractionation.', marks: 2, markScheme: `• An isotonic solution has the same water potential as the cell contents (1)\n• This prevents organelles from bursting (in a hypotonic solution) or shrinking (in a hypertonic solution) by osmosis (1)` },
      { q: 'A student uses a t-test and obtains p = 0.03. Explain what this means.', marks: 2, markScheme: `• There is a 3% probability that the difference between the two means is due to chance (1)\n• Since p < 0.05, the result is statistically significant — the null hypothesis is rejected and there is a significant difference (1)` },
      { q: 'Explain the advantages of using a data logger rather than manual recording when measuring temperature changes in an experiment.', marks: 2, markScheme: `• A data logger can take readings at precise, regular time intervals without human error (1)\n• It records data continuously and can detect rapid changes that a human observer might miss (1)` },
      { q: 'Explain why a cold solution is used during homogenisation in cell fractionation.', marks: 2, markScheme: `• Low temperature reduces enzyme activity / slows down hydrolytic enzyme action (1)\n• This prevents autolysis / breakdown of organelles by their own enzymes (1)` },
      { q: 'Describe one limitation of using a correlation to infer a causal relationship between two variables.', marks: 2, markScheme: `• A correlation shows that two variables change together, but does not prove one causes the other (1)\n• There may be a third/confounding variable responsible for the observed relationship (1)` },
      { q: 'Explain why a student should use a spirometer in conjunction with soda lime when measuring oxygen consumption.', marks: 2, markScheme: `• Soda lime absorbs the CO₂ produced during respiration (1)\n• This means only O₂ changes are measured, so the decrease in gas volume on the spirometer trace directly represents oxygen consumption (1)` },
      { q: 'Describe how to use the Spearman rank correlation test to analyse data.', marks: 3, markScheme: `• Rank the data for each variable separately and calculate the difference (d) between ranks for each pair (1)\n• Square each difference and sum them (Σd²), then apply the formula rs = 1 − (6Σd² / n(n²−1)) (1)\n• Compare the calculated rs value to the critical value for the appropriate n and significance level — if rs exceeds the critical value, there is a significant correlation (1)` },
      { q: 'Explain why percentage change is often more useful than absolute change when comparing results between different experiments.', marks: 2, markScheme: `• Percentage change accounts for differences in starting values / initial amounts (1)\n• This allows a fair comparison between experiments with different baselines, removing the effect of scale (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── B2 */
  'B2': {
    name: 'Cells, Chemicals and Transport',
    questions: [
      { q: 'State two functions of the cell membrane.', marks: 2, markScheme: `• Controls what enters and leaves the cell / selectively permeable barrier (1)\n• Cell signalling / contains receptors for hormones and other molecules (1)` },
      { q: 'State the function of the nucleus.', marks: 1, markScheme: `• Contains DNA/genetic material and controls cell activities (gene expression / protein synthesis) (1)` },
      { q: 'State the function of mitochondria.', marks: 1, markScheme: `• Site of aerobic respiration / produces ATP (1)` },
      { q: 'State the function of ribosomes.', marks: 1, markScheme: `• Site of protein synthesis / translation of mRNA into polypeptides (1)` },
      { q: 'State two structural differences between plant and animal cells.', marks: 2, markScheme: `• Plant cells have a cellulose cell wall; animal cells do not (1)\n• Plant cells have chloroplasts for photosynthesis; animal cells do not (1)\n(Also accept: large permanent vacuole in plant cells)` },
      { q: 'State the difference between magnification and resolution.', marks: 2, markScheme: `• Magnification is how much larger an image appears compared to the actual object (1)\n• Resolution is the ability to distinguish between two separate points / the minimum distance apart two objects can be and still be seen as distinct (1)` },
      { q: 'Calculate the magnification if an image of a cell is 30 mm and the actual cell is 0.03 mm.', marks: 2, markScheme: `• Magnification = image size / actual size (1)\n• = 30 / 0.03 = ×1000 (1)` },
      { q: 'Describe the structure of a phospholipid.', marks: 2, markScheme: `• A glycerol molecule attached to two fatty acid chains (hydrophobic tails) and one phosphate group (hydrophilic head) (1)\n• The molecule is amphipathic — having both hydrophilic and hydrophobic regions (1)` },
      { q: 'Explain why phospholipids spontaneously form a bilayer in aqueous environments.', marks: 3, markScheme: `• The hydrophilic phosphate heads are attracted to water and face outward (1)\n• The hydrophobic fatty acid tails are repelled by water and face inward (1)\n• This arrangement is thermodynamically stable and forms a barrier to polar/charged substances (1)` },
      { q: 'State the role of cholesterol in cell membranes.', marks: 2, markScheme: `• Regulates membrane fluidity — at high temperatures it reduces fluidity by restricting phospholipid movement (1)\n• At low temperatures it prevents the membrane from becoming too rigid by preventing phospholipids from packing closely (1)` },
      { q: 'Describe the fluid mosaic model of membrane structure.', marks: 3, markScheme: `• Phospholipid bilayer forms the basis of the membrane (1)\n• Proteins (integral spanning the membrane; peripheral on the surface) are scattered throughout in a mosaic pattern (1)\n• "Fluid" because phospholipids and proteins can move laterally within the bilayer (1)` },
      { q: 'State the difference between diffusion and osmosis.', marks: 2, markScheme: `• Diffusion is the net movement of particles (molecules/ions) from high to low concentration (1)\n• Osmosis is specifically the net movement of water molecules across a partially permeable membrane from high to low water potential (1)` },
      { q: 'Explain what happens to an animal cell placed in pure water.', marks: 3, markScheme: `• Water moves into the cell by osmosis (from higher water potential outside to lower inside) (1)\n• The cell swells as it takes in water (1)\n• Eventually the cell may burst (lysis) because it has no cell wall to resist the pressure (1)` },
      { q: 'Explain what happens to a plant cell placed in a concentrated sucrose solution.', marks: 3, markScheme: `• Water moves out of the cell by osmosis (from higher water potential inside to lower outside) (1)\n• The vacuole shrinks and the cell membrane pulls away from the cell wall (plasmolysis) (1)\n• The cell wall is rigid and permeable so maintains its shape, but the cell becomes flaccid (1)` },
      { q: 'Explain how active transport differs from facilitated diffusion.', marks: 3, markScheme: `• Active transport moves substances against the concentration gradient; facilitated diffusion moves them down the gradient (1)\n• Active transport requires metabolic energy (ATP); facilitated diffusion is passive (1)\n• Both use carrier proteins, but facilitated diffusion can also use channel proteins (1)` },
      { q: 'Describe the process of endocytosis.', marks: 3, markScheme: `• The cell membrane invaginates (folds inward) around the substance to be taken in (1)\n• A vesicle is pinched off from the membrane, enclosing the substance inside the cell (1)\n• Requires ATP / is an active process (1)` },
      { q: 'State the four levels of protein structure.', marks: 4, markScheme: `• Primary: the sequence of amino acids in the polypeptide chain (1)\n• Secondary: local folding into alpha helices or beta pleated sheets, held by hydrogen bonds between backbone atoms (1)\n• Tertiary: the overall 3D shape of a single polypeptide, maintained by R-group interactions (H-bonds, ionic bonds, disulfide bridges, hydrophobic interactions) (1)\n• Quaternary: the arrangement of multiple polypeptide subunits into a functional protein (1)` },
      { q: 'Explain how enzyme specificity is determined.', marks: 2, markScheme: `• The shape of the active site is complementary to the shape of the specific substrate (1)\n• This is determined by the precise tertiary structure (3D folding) of the enzyme protein, which depends on the amino acid sequence (1)` },
      { q: 'Explain how temperature affects enzyme activity, including what happens above the optimum.', marks: 4, markScheme: `• As temperature increases, kinetic energy of molecules increases, so collisions between enzyme and substrate are more frequent and energetic — rate increases (1)\n• At the optimum temperature, the rate is maximum (1)\n• Above the optimum, increased vibration breaks weak bonds (H-bonds, ionic bonds) maintaining the tertiary structure (1)\n• The active site changes shape (denaturation) — substrate can no longer bind, and rate decreases sharply (1)` },
      { q: 'Explain the difference between competitive and non-competitive inhibition.', marks: 4, markScheme: `• Competitive inhibitor: has a similar shape to the substrate and binds to the active site, blocking the substrate (1)\n• Can be overcome by increasing substrate concentration (1)\n• Non-competitive inhibitor: binds to an allosteric site (not the active site), causing a conformational change that alters the active site shape (1)\n• Cannot be overcome by increasing substrate concentration — Vmax is reduced (1)` },
      { q: 'Describe the Biuret test for proteins.', marks: 3, markScheme: `• Add sodium hydroxide (NaOH) solution to the sample to make it alkaline (1)\n• Add copper sulfate (CuSO₄) solution (1)\n• A purple/violet colour indicates protein is present (Cu²⁺ ions form a complex with peptide bonds); blue colour = no protein (1)` },
      { q: 'Describe the Benedict\'s test for reducing sugars.', marks: 3, markScheme: `• Add Benedict\'s reagent (blue) to the sample (1)\n• Heat in a water bath at approximately 80°C for 2-5 minutes (1)\n• A colour change from blue → green → yellow → orange → brick-red indicates reducing sugar is present; the more sugar, the further along this colour series (1)` },
      { q: 'Explain how cell fractionation and ultracentrifugation are used to isolate organelles.', marks: 4, markScheme: `• Cells are homogenised (broken open) in cold, isotonic, buffered solution to prevent damage to organelles (1)\n• The homogenate is filtered to remove debris (1)\n• Differential centrifugation: spun at increasing speeds — heaviest organelles (nuclei) sediment first at low speed, then mitochondria, then ER/ribosomes at highest speed (1)\n• Each pellet contains a different organelle fraction which can be studied separately (1)` },
      { q: 'Explain how surface area to volume ratio affects the need for specialised exchange surfaces in organisms.', marks: 3, markScheme: `• Small organisms have a large SA:V ratio — diffusion alone is sufficient for exchange (1)\n• As organisms increase in size, SA:V ratio decreases — diffusion across the body surface is too slow for metabolic needs (1)\n• Therefore larger organisms require specialised exchange surfaces (lungs, villi, gills) with adaptations to increase SA and reduce diffusion distance (1)` },
      { q: 'Describe the role of carrier proteins in facilitated diffusion.', marks: 3, markScheme: `• Specific molecule binds to the carrier protein on one side of the membrane (1)\n• The carrier protein changes shape/conformation (1)\n• The molecule is released on the other side of the membrane — no ATP required, movement is down the concentration gradient (1)` },
      { q: 'Explain what is meant by Vmax and Km in enzyme kinetics.', marks: 4, markScheme: `• Vmax is the maximum rate of reaction when all enzyme active sites are saturated with substrate (1)\n• It can be increased by adding more enzyme (1)\n• Km is the substrate concentration at which the rate is half of Vmax (1)\n• A low Km indicates high enzyme-substrate affinity (the enzyme reaches half Vmax at a lower substrate concentration) (1)` },
      { q: 'Explain how co-transport works in the absorption of glucose in the small intestine.', marks: 4, markScheme: `• Na⁺/K⁺ ATPase pumps on the basal membrane pump Na⁺ out of the epithelial cell, maintaining a low intracellular Na⁺ concentration (1)\n• Na⁺ diffuses back into the cell through a sodium-glucose co-transporter on the apical membrane (down its concentration gradient) (1)\n• Glucose is carried into the cell alongside Na⁺ against its own concentration gradient (secondary active transport) (1)\n• Glucose then moves out of the cell into the blood by facilitated diffusion through GLUT transporters on the basal membrane (1)` },
      { q: 'Describe how transmission electron microscopy (TEM) differs from scanning electron microscopy (SEM).', marks: 3, markScheme: `• TEM passes electrons through a thin section of the specimen — produces 2D images of internal ultrastructure at very high resolution (1)\n• SEM bounces electrons off the surface of a specimen — produces 3D images of surface features (1)\n• TEM has higher resolution than SEM but specimens must be very thin; SEM gives topographical information but lower resolution (1)` },
      { q: 'Explain why enzymes are described as biological catalysts.', marks: 2, markScheme: `• They speed up chemical reactions by lowering the activation energy required (1)\n• They are not consumed in the reaction and can be reused / they are made of protein and produced by living cells (1)` },
      { q: 'Explain how the tertiary structure of a protein determines its function.', marks: 3, markScheme: `• The R-group interactions fold the polypeptide into a specific 3D shape (1)\n• This creates a precisely shaped active site (enzymes) or binding site (antibodies/receptors) (1)\n• If the tertiary structure is altered (e.g., by denaturation), the specific shape is lost and the protein cannot function (1)` },
      { q: 'Describe one piece of evidence that supports the fluid mosaic model.', marks: 2, markScheme: `• Freeze-fracture electron microscopy: splitting the membrane reveals proteins embedded within the bilayer, not just on the surface (1)\n• This confirms the "mosaic" of integral proteins scattered through a phospholipid bilayer, supporting the model (1)` },
      { q: 'Explain why water is important as a solvent in biological systems.', marks: 3, markScheme: `• Water is polar, so it can dissolve many ionic and polar substances, allowing chemical reactions to occur in solution (1)\n• It acts as a transport medium (blood plasma, xylem sap) carrying dissolved substances around organisms (1)\n• Metabolic reactions (hydrolysis, condensation) occur in aqueous solution within cells (1)` },
      { q: 'Describe the emulsion test for lipids.', marks: 2, markScheme: `• Dissolve the sample in ethanol, then pour the ethanol solution into water (1)\n• A cloudy white emulsion indicates lipid is present (lipid forms tiny droplets suspended in water) (1)` },
      { q: 'Explain why cellulose is insoluble and structurally strong.', marks: 3, markScheme: `• Cellulose is made of β-glucose monomers — alternate monomers are rotated 180°, forming straight chains (1)\n• Adjacent chains form many hydrogen bonds between -OH groups, creating strong microfibrils (1)\n• The extensive hydrogen bonding between chains makes cellulose insoluble and provides tensile strength to plant cell walls (1)` },
      { q: 'Describe the test for starch and state the positive result.', marks: 2, markScheme: `• Add iodine solution (potassium iodide) to the sample (1)\n• A colour change from yellow-brown to blue-black indicates starch is present (1)` },
      { q: 'Explain the difference between a glycosidic bond and a peptide bond.', marks: 2, markScheme: `• A glycosidic bond forms between two monosaccharides (sugar monomers) by a condensation reaction (1)\n• A peptide bond forms between two amino acids (between the carboxyl group of one and the amino group of the next) by a condensation reaction (1)` },
      { q: 'Explain how channel proteins facilitate the transport of ions across membranes.', marks: 3, markScheme: `• Channel proteins form a water-filled pore through the membrane (1)\n• The channel is usually specific to particular ions due to its diameter and charge of the lining (1)\n• Ions pass through down their electrochemical gradient — this is passive and does not require ATP (1)` },
      { q: 'State what is meant by a saturated and an unsaturated fatty acid.', marks: 2, markScheme: `• Saturated: no carbon-carbon double bonds in the hydrocarbon tail — all carbons bonded to maximum hydrogen atoms (1)\n• Unsaturated: one or more C=C double bonds in the tail, causing kinks that prevent close packing (1)` },
      { q: 'Explain why increasing temperature above 40°C increases membrane permeability.', marks: 3, markScheme: `• Phospholipids gain kinetic energy and move more, increasing fluidity (1)\n• Protein channels/carriers may denature, losing their specific shape (1)\n• Gaps appear in the membrane, allowing substances to leak out that would normally be retained (1)` },
      { q: 'Describe how water potential is affected by the addition of solute.', marks: 2, markScheme: `• Adding solute lowers/makes more negative the water potential of a solution (1)\n• Solute molecules attract water molecules (reduce their free energy/tendency to move), so water potential decreases from the pure water maximum of 0 kPa (1)` },
      { q: 'A cell with ψ = -400 kPa is placed in a solution with ψ = -200 kPa. In which direction will water move?', marks: 2, markScheme: `• Water moves from the solution (higher ψ, -200 kPa) into the cell (lower ψ, -400 kPa) (1)\n• Water always moves from higher to lower water potential by osmosis (1)` },
      { q: 'Explain the role of ATP in active transport.', marks: 2, markScheme: `• ATP is hydrolysed by the carrier protein (which acts as an ATPase) (1)\n• The energy released causes the carrier protein to change shape, moving the molecule/ion against its concentration gradient across the membrane (1)` },
      { q: 'Explain why prokaryotic cells are generally smaller than eukaryotic cells.', marks: 2, markScheme: `• Prokaryotes lack membrane-bound organelles, so metabolic compartmentalisation is limited (1)\n• Their simpler internal organisation means they function efficiently at smaller sizes; eukaryotes need more volume for complex organelles (1)` },
      { q: 'Describe the structure of starch and explain how it is suited to its storage function.', marks: 4, markScheme: `• Starch is made of α-glucose monomers joined by 1-4 glycosidic bonds (amylose) with 1-6 branches (amylopectin) (1)\n• Amylose coils into a helix — compact for storage (1)\n• Amylopectin is branched — many terminal ends allow rapid hydrolysis when glucose is needed (1)\n• Starch is insoluble — does not affect water potential of the cell / does not diffuse out (1)` },
      { q: 'State one advantage and one disadvantage of using light microscopy to study cells.', marks: 2, markScheme: `• Advantage: can observe living cells / inexpensive / quick / portable (1)\n• Disadvantage: limited resolution (~200 nm) — cannot see ultrastructure of organelles (1)` },
      { q: 'Explain why glycogen is more branched than starch and how this relates to its function.', marks: 3, markScheme: `• Glycogen has many 1-6 branches (more than amylopectin) (1)\n• This means there are many terminal glucose units that can be hydrolysed simultaneously (1)\n• Animals need rapid access to glucose for respiration (e.g., during exercise), so many branch ends allow quick mobilisation of glucose (1)` },
      { q: 'Describe how a student could investigate the effect of temperature on membrane permeability using beetroot.', marks: 4, markScheme: `• Cut equal-sized beetroot cylinders, wash to remove surface pigment (1)\n• Place cylinders in water baths at different temperatures for the same time (1)\n• Remove cylinders and measure the absorbance/colour intensity of the surrounding solution using a colorimeter (1)\n• Higher absorbance indicates more betacyanin pigment leaked out = greater membrane permeability at that temperature (1)` },
      { q: 'Explain why the rate of facilitated diffusion plateaus at high substrate concentration.', marks: 2, markScheme: `• At high concentrations, all available carrier/channel proteins are occupied (saturated) (1)\n• Increasing concentration further cannot increase the rate because there are no more transport proteins available — the rate reaches a maximum (1)` },
      { q: 'Compare the structure of a triglyceride and a phospholipid.', marks: 3, markScheme: `• Both contain glycerol and fatty acid chains linked by ester bonds (1)\n• Triglyceride: glycerol + 3 fatty acids; phospholipid: glycerol + 2 fatty acids + 1 phosphate group (1)\n• Phospholipid is amphipathic (hydrophilic head, hydrophobic tail); triglyceride is entirely hydrophobic (1)` },
      { q: 'Explain the role of hydrogen bonds in maintaining protein secondary structure.', marks: 2, markScheme: `• Hydrogen bonds form between the C=O group of one amino acid and the N-H group of another amino acid in the polypeptide backbone (1)\n• These regular H-bonds stabilise alpha helices and beta pleated sheets (secondary structure) (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── B3 */
  'B3': {
    name: 'Cell Division, Development and Disease',
    questions: [
      { q: 'State two reasons why cells undergo mitosis.', marks: 2, markScheme: `• Growth — increasing the number of cells (1)\n• Repair/replacement of damaged or worn-out cells (1)` },
      { q: 'State the number of chromosomes in a human gamete.', marks: 1, markScheme: `• 23 (haploid number) (1)` },
      { q: 'State what happens during the S phase of interphase.', marks: 1, markScheme: `• DNA is replicated — each chromosome becomes two sister chromatids joined at the centromere (1)` },
      { q: 'Describe what happens during prophase of mitosis.', marks: 3, markScheme: `• Chromosomes condense/become visible as distinct structures (1)\n• The nuclear envelope begins to break down (1)\n• Centrioles move to opposite poles and spindle fibres begin to form (1)` },
      { q: 'Describe what happens during anaphase of mitosis.', marks: 2, markScheme: `• Centromeres divide — sister chromatids are pulled apart (1)\n• Chromatids are pulled to opposite poles of the cell by shortening spindle fibres (1)` },
      { q: 'Explain why meiosis is important for sexually reproducing organisms.', marks: 3, markScheme: `• Meiosis produces haploid gametes (1)\n• When gametes fuse at fertilisation, the diploid number is restored (1)\n• Meiosis introduces genetic variation through crossing over and independent assortment — important for evolution/adaptation (1)` },
      { q: 'Explain how independent assortment leads to genetic variation.', marks: 3, markScheme: `• In metaphase I, homologous pairs line up randomly at the cell equator (1)\n• The orientation of each pair is independent of others (1)\n• This means each gamete receives a different combination of maternal and paternal chromosomes — for humans, 2²³ possible combinations (1)` },
      { q: 'Describe crossing over and explain when it occurs.', marks: 3, markScheme: `• Occurs during prophase I of meiosis when homologous chromosomes are paired (bivalents) (1)\n• Non-sister chromatids break and reconnect with the other homologue at points called chiasmata (1)\n• Sections of DNA are exchanged, producing recombinant chromosomes with new allele combinations (1)` },
      { q: 'State what is meant by differentiation.', marks: 2, markScheme: `• The process by which an unspecialised cell becomes specialised (1)\n• It develops specific structures and functions by expressing certain genes and not others (1)` },
      { q: 'Explain the difference between totipotent and pluripotent stem cells.', marks: 2, markScheme: `• Totipotent: can differentiate into any cell type including extraembryonic tissue (placenta) — found in early embryo/zygote (1)\n• Pluripotent: can differentiate into any cell type of the body but not extraembryonic tissue — found in inner cell mass of blastocyst (1)` },
      { q: 'Explain what is meant by apoptosis and give one example of its role in development.', marks: 3, markScheme: `• Apoptosis is programmed/controlled cell death (1)\n• The cell is broken down in an orderly way without triggering inflammation (1)\n• Example: removal of webbing between fingers during embryonic development / removal of the tadpole tail during metamorphosis (1)` },
      { q: 'State two physical barriers that prevent pathogen entry into the body.', marks: 2, markScheme: `• Skin — acts as a physical barrier; dead outer layer difficult for pathogens to penetrate (1)\n• Mucous membranes — mucus traps pathogens in the respiratory tract; cilia move mucus away (1)` },
      { q: 'Describe the process of phagocytosis.', marks: 4, markScheme: `• Phagocyte is attracted to the pathogen (chemotaxis) (1)\n• The phagocyte engulfs the pathogen by extending pseudopodia around it, forming a phagosome (1)\n• Lysosomes fuse with the phagosome, releasing hydrolytic enzymes (1)\n• The pathogen is digested/destroyed; antigens may be presented on the phagocyte surface (antigen presentation) (1)` },
      { q: 'Explain the role of T helper cells in the immune response.', marks: 3, markScheme: `• T helper cells recognise antigens presented by antigen-presenting cells (APCs) via MHC II (1)\n• They become activated and release cytokines (1)\n• Cytokines stimulate B cells to divide and differentiate into plasma cells, and activate cytotoxic T cells — coordinating the adaptive response (1)` },
      { q: 'Explain the difference between the primary and secondary immune response.', marks: 4, markScheme: `• Primary response: first exposure to an antigen — slow because there are few specific B/T cells; takes days to produce sufficient antibodies (1)\n• During primary response, memory cells (B and T) are produced (1)\n• Secondary response: re-exposure to the same antigen — faster, stronger, and longer-lasting because memory cells rapidly divide and differentiate (1)\n• More antibodies are produced more quickly, often preventing symptoms from developing (1)` },
      { q: 'Explain how cytotoxic T cells destroy infected cells.', marks: 3, markScheme: `• Cytotoxic T cells recognise infected cells displaying foreign antigens on MHC I molecules (1)\n• They bind to the infected cell and release perforin, which creates pores in the target cell membrane (1)\n• Granzymes enter through the pores and trigger apoptosis (programmed cell death) of the infected cell (1)` },
      { q: 'Describe how monoclonal antibodies are produced.', marks: 4, markScheme: `• A mouse is injected with the target antigen; B cells producing the desired antibody are isolated from the spleen (1)\n• B cells are fused with myeloma (tumour) cells to produce hybridoma cells (1)\n• Hybridomas are screened for production of the correct antibody and selected clones are cultured (1)\n• Hybridomas divide indefinitely and produce large quantities of identical (monoclonal) antibodies (1)` },
      { q: 'Explain the role of tumour suppressor genes in preventing cancer.', marks: 3, markScheme: `• Tumour suppressor genes code for proteins that inhibit/slow the cell cycle at checkpoints (1)\n• They can trigger DNA repair mechanisms or apoptosis if DNA damage is detected (1)\n• Loss-of-function mutations in tumour suppressor genes (e.g., p53) remove these controls, allowing damaged cells to continue dividing (1)` },
      { q: 'Explain the difference between a benign and a malignant tumour.', marks: 3, markScheme: `• Benign: grows slowly, encapsulated, does not invade surrounding tissue, does not metastasise (1)\n• Malignant: grows rapidly, not encapsulated, invades surrounding tissue (1)\n• Malignant tumours can metastasise — cells break off and spread via blood/lymph to form secondary tumours at distant sites (1)` },
      { q: 'State what is meant by "metastasis".', marks: 2, markScheme: `• The spread of cancer cells from the primary tumour to other parts of the body (1)\n• Cancer cells travel through the blood or lymphatic system and establish secondary tumours at new sites (1)` },
      { q: 'Explain why antibiotic resistance is an example of natural selection.', marks: 4, markScheme: `• Random mutations in bacteria may confer resistance to an antibiotic (variation) (1)\n• When antibiotics are used, susceptible bacteria are killed but resistant ones survive (selection pressure) (1)\n• Resistant bacteria reproduce and pass on the resistance allele/gene (inheritance) (1)\n• Over time the resistant allele becomes more frequent in the population (evolution) (1)` },
      { q: 'Explain why antibiotics cannot be used to treat viral infections.', marks: 3, markScheme: `• Antibiotics target bacterial structures/processes such as cell walls (peptidoglycan synthesis) and bacterial ribosomes (1)\n• Viruses do not have cell walls or their own ribosomes — they replicate inside host cells using host machinery (1)\n• Therefore antibiotics have no target in viruses and are ineffective against them (1)` },
      { q: 'Describe how vaccination leads to immunity.', marks: 4, markScheme: `• A vaccine contains weakened/inactivated pathogen or isolated antigens (does not cause disease) (1)\n• The immune system recognises the antigens and mounts a primary immune response (B and T cell activation) (1)\n• Antibodies are produced and memory cells (B and T) are formed (1)\n• On future exposure to the real pathogen, memory cells rapidly produce a secondary response, destroying the pathogen before symptoms develop (1)` },
      { q: 'Explain what is meant by "herd immunity" and why it is important.', marks: 3, markScheme: `• Herd immunity occurs when a high proportion of a population is vaccinated/immune (1)\n• This reduces the transmission of the pathogen because there are fewer susceptible hosts (1)\n• It protects individuals who cannot be vaccinated (e.g., immunocompromised, very young) by reducing their chance of exposure (1)` },
      { q: 'Explain the role of cell cycle checkpoints in preventing cancer.', marks: 3, markScheme: `• Checkpoints are control points in the cell cycle where conditions are assessed before proceeding (e.g., G1, G2, metaphase) (1)\n• They check for DNA damage, correct chromosome attachment, and adequate cell size/nutrients (1)\n• If problems are detected, the cell cycle is halted for repair or the cell undergoes apoptosis — preventing damaged cells from dividing and potentially becoming cancerous (1)` },
      { q: 'State what is meant by an oncogene and explain how it differs from a proto-oncogene.', marks: 3, markScheme: `• A proto-oncogene is a normal gene that codes for proteins promoting cell growth/division (e.g., growth factors, signal proteins) (1)\n• An oncogene is a mutated form of a proto-oncogene with increased/unregulated activity (gain of function) (1)\n• Oncogenes stimulate uncontrolled cell division, contributing to cancer development (1)` },
      { q: 'Explain what is meant by an autoimmune disease and give one example.', marks: 3, markScheme: `• An autoimmune disease is a condition where the immune system fails to distinguish self from non-self (1)\n• The immune system attacks the body\'s own cells/tissues by producing antibodies against self-antigens (1)\n• Example: Type 1 diabetes (immune system destroys β-cells of the pancreas) / rheumatoid arthritis / lupus / multiple sclerosis (1)` },
      { q: 'Describe the structure of a virus.', marks: 3, markScheme: `• Genetic material (DNA or RNA, single or double-stranded) at the core (1)\n• Protein coat (capsid) made of capsomere subunits surrounding the genetic material (1)\n• Some viruses have a lipid envelope derived from the host cell membrane, with glycoprotein spikes for attachment (1)` },
      { q: 'Explain why non-disjunction during meiosis can lead to Down syndrome.', marks: 3, markScheme: `• Non-disjunction is the failure of homologous chromosomes (meiosis I) or sister chromatids (meiosis II) to separate properly (1)\n• This produces gametes with an extra copy of chromosome 21 (1)\n• When this gamete is fertilised, the offspring has three copies of chromosome 21 (trisomy 21) — resulting in Down syndrome (1)` },
      { q: 'Explain why cancer risk increases with age.', marks: 3, markScheme: `• Cancer requires multiple mutations in genes controlling the cell cycle (multi-hit hypothesis) (1)\n• Over a lifetime, more mutations accumulate from DNA replication errors and environmental mutagens (1)\n• With age, DNA repair mechanisms may become less efficient and immune surveillance may decline (1)` },
      { q: 'Describe the role of the immune system in transplant rejection.', marks: 3, markScheme: `• Transplanted tissue has different surface antigens (MHC markers) from the recipient (1)\n• The recipient\'s immune system recognises these as foreign/non-self (1)\n• T cells attack the transplanted tissue, causing inflammation and destruction (rejection) — immunosuppressant drugs are used to prevent this (1)` },
      { q: 'Explain why tissue typing is important before organ transplantation.', marks: 2, markScheme: `• Tissue typing matches donor and recipient MHC/HLA markers as closely as possible (1)\n• A closer match reduces the likelihood of immune rejection and the need for immunosuppressant drugs (1)` },
      { q: 'Explain how antigenic variation in influenza challenges vaccine development.', marks: 3, markScheme: `• The influenza virus frequently mutates its surface antigens (haemagglutinin and neuraminidase) — antigenic drift (1)\n• Memory cells from previous infection/vaccination do not recognise the new surface antigens (1)\n• New vaccines must be developed each year to match the current circulating strains (1)` },
      { q: 'State two risk factors for cancer.', marks: 2, markScheme: `• Smoking / tobacco (carcinogens cause DNA mutations) (1)\n• UV radiation / ionising radiation / certain chemicals / obesity / genetic predisposition / certain viral infections (HPV, Hepatitis B) (any 1 for 1)` },
      { q: 'Explain what is meant by "clonal expansion" in the immune response.', marks: 2, markScheme: `• When a specific lymphocyte (B or T cell) is activated by its complementary antigen, it divides rapidly by mitosis (1)\n• This produces a large clone of identical cells all specific to the same antigen, allowing a large-scale response (1)` },
      { q: 'Describe how induced pluripotent stem cells (iPSCs) are produced.', marks: 3, markScheme: `• Adult differentiated cells (e.g., skin fibroblasts) are collected from the patient (1)\n• Specific transcription factors (e.g., Oct4, Sox2, Klf4, c-Myc) are introduced using viral vectors or other methods (1)\n• These reprogramme the cells back to a pluripotent state, capable of differentiating into many cell types (1)` },
      { q: 'Explain one advantage of iPSCs over embryonic stem cells.', marks: 2, markScheme: `• iPSCs can be derived from the patient\'s own cells, avoiding immune rejection (1)\n• Their use does not require the destruction of embryos, reducing ethical objections (1)` },
      { q: 'State the difference between active and passive immunity.', marks: 2, markScheme: `• Active immunity: the individual\'s own immune system produces antibodies and memory cells (long-lasting) (1)\n• Passive immunity: antibodies are received from another source (e.g., mother to baby via placenta/breast milk, or injection) — provides immediate but short-term protection as no memory cells are produced (1)` },
      { q: 'Explain how the cell cycle is regulated by cyclins and CDKs.', marks: 3, markScheme: `• Cyclins are proteins whose concentration fluctuates during the cell cycle (1)\n• Cyclins bind to and activate cyclin-dependent kinases (CDKs), forming cyclin-CDK complexes (1)\n• These complexes phosphorylate target proteins that drive the cell through checkpoints and from one phase to the next — without appropriate cyclin-CDK activity the cell cannot progress (1)` },
      { q: 'Discuss one ethical concern about genetic screening of embryos for disease.', marks: 3, markScheme: `• Genetic screening can identify embryos carrying alleles for genetic disorders (e.g., cystic fibrosis) (1)\n• Ethical concern: it may lead to selection/deselection of embryos, raising questions about whether this constitutes discrimination against disabled people or "designer babies" (1)\n• Counter-argument: it can prevent severe suffering and reduce the burden of genetic disease on families (1)` },
      { q: 'Explain the role of inflammation as part of the innate immune response.', marks: 3, markScheme: `• Damaged cells and mast cells release histamine and cytokines (1)\n• This causes vasodilation and increased capillary permeability, bringing more blood (containing phagocytes and clotting factors) to the area (1)\n• Inflammation isolates the infected area, enhances phagocyte recruitment, and prevents spread of pathogens (1)` },
      { q: 'State what is meant by "antigen presentation" and explain its importance.', marks: 3, markScheme: `• After phagocytosis, fragments of pathogen antigens are displayed on the phagocyte surface bound to MHC II molecules (1)\n• The phagocyte becomes an antigen-presenting cell (APC) (1)\n• This is essential for activating T helper cells, which then coordinate the adaptive immune response (without antigen presentation, the specific response cannot be initiated) (1)` },
      { q: 'Explain why a person with HIV becomes immunodeficient over time.', marks: 3, markScheme: `• HIV infects and destroys CD4+ T helper cells (1)\n• As T helper cell numbers decline, the immune system loses the ability to coordinate adaptive responses (B cell activation, cytotoxic T cell activation) (1)\n• Eventually the immune system cannot fight opportunistic infections, leading to AIDS (1)` },
      { q: 'Describe one use of monoclonal antibodies in medicine.', marks: 3, markScheme: `• Example: pregnancy testing — monoclonal antibodies specific to hCG (human chorionic gonadotrophin) bind to the hormone in urine (1)\n• The antibody-antigen complex is detected by a colour change on the test strip (1)\n• Monoclonal antibodies are highly specific, allowing precise detection of the target molecule (1)\n(Also accept: cancer treatment with targeted drug delivery, diagnostic imaging, etc.)` },
      { q: 'Explain why the immune response to a secondary infection is faster and stronger.', marks: 3, markScheme: `• Memory B cells and memory T cells produced during the primary response persist in the body (1)\n• On re-exposure to the same antigen, memory cells are rapidly activated and undergo clonal expansion (1)\n• More antibodies are produced faster and in greater quantity — often clearing the pathogen before symptoms develop (1)` },
      { q: 'Describe the evidence that cancer development is a multi-step process.', marks: 3, markScheme: `• Cancer typically requires mutations in several genes (both oncogenes and tumour suppressor genes) (1)\n• Studies show that cancer incidence increases with age, consistent with accumulation of mutations over time (1)\n• Some cancers progress through identifiable stages (e.g., colon polyp → adenoma → carcinoma), each associated with additional mutations (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── B4 */
  'B4': {
    name: 'Energy, Reproduction and Populations',
    questions: [
      { q: 'State the word equation for photosynthesis.', marks: 1, markScheme: `• Carbon dioxide + water → glucose + oxygen (using light energy) (1)` },
      { q: 'State where the light-dependent reactions of photosynthesis occur.', marks: 1, markScheme: `• Thylakoid membranes of the chloroplasts (1)` },
      { q: 'State where the Calvin cycle occurs.', marks: 1, markScheme: `• The stroma of the chloroplast (1)` },
      { q: 'State the products of the light-dependent reactions.', marks: 3, markScheme: `• ATP (1)\n• Reduced NADP / NADPH (1)\n• Oxygen (from photolysis of water) (1)` },
      { q: 'State the substrate and products of glycolysis.', marks: 3, markScheme: `• Substrate: glucose (6C) (1)\n• Products: 2 × pyruvate (3C), net 2 ATP, 2 × reduced NAD (1)\n• Occurs in the cytoplasm (1)` },
      { q: 'State where the Krebs cycle occurs and name one of its products.', marks: 2, markScheme: `• Mitochondrial matrix (1)\n• Products (any one): reduced NAD, reduced FAD, ATP (by substrate-level phosphorylation), CO₂ (1)` },
      { q: 'State what is meant by the term "limiting factor" in photosynthesis.', marks: 1, markScheme: `• A factor that, when in short supply, limits the rate of photosynthesis — increasing it would increase the rate (1)` },
      { q: 'State the net ATP yield from one molecule of glucose during glycolysis.', marks: 1, markScheme: `• Net 2 ATP (4 produced minus 2 used in phosphorylation of glucose) (1)` },
      { q: 'Describe the role of oxygen as the final electron acceptor in the electron transport chain.', marks: 2, markScheme: `• Oxygen accepts electrons and hydrogen ions (H⁺) at the end of the electron transport chain (1)\n• This forms water and is essential to keep the chain functioning — without oxygen, electrons cannot be passed along, and ATP production via oxidative phosphorylation stops (1)` },
      { q: 'Describe the link reaction.', marks: 3, markScheme: `• Pyruvate (3C) moves from the cytoplasm into the mitochondrial matrix (1)\n• Pyruvate is decarboxylated (CO₂ removed) and oxidised (hydrogen removed, reducing NAD) (1)\n• The 2C acetyl group combines with coenzyme A to form acetyl CoA, which enters the Krebs cycle (1)` },
      { q: 'Describe the main events of the Krebs cycle.', marks: 4, markScheme: `• Acetyl CoA (2C) combines with oxaloacetate (4C) to form citrate (6C) (1)\n• Citrate is progressively decarboxylated (2 × CO₂ released) and oxidised (hydrogen removed) (1)\n• Reduced NAD (×3) and reduced FAD (×1) are produced per turn (1)\n• 1 ATP is produced per turn by substrate-level phosphorylation; oxaloacetate is regenerated (1)` },
      { q: 'Explain chemiosmosis and the role of ATP synthase.', marks: 4, markScheme: `• Electrons pass along the electron transport chain (inner mitochondrial membrane), releasing energy (1)\n• This energy pumps H⁺ ions from the matrix into the intermembrane space, building a proton gradient (1)\n• H⁺ ions flow back through ATP synthase (down the electrochemical gradient) (1)\n• The flow of H⁺ drives ATP synthase to catalyse the phosphorylation of ADP to ATP (chemiosmosis) (1)` },
      { q: 'Explain why anaerobic respiration produces far less ATP than aerobic respiration.', marks: 3, markScheme: `• Without oxygen, the electron transport chain and Krebs cycle cannot function (1)\n• Only glycolysis operates, yielding net 2 ATP per glucose (vs ~30-32 from aerobic) (1)\n• Pyruvate is converted to lactate (animals) or ethanol + CO₂ (yeast) to regenerate NAD so glycolysis can continue — but most chemical energy remains locked in these products (1)` },
      { q: 'Explain what is meant by the respiratory quotient (RQ) and state the RQ for carbohydrate.', marks: 2, markScheme: `• RQ = CO₂ produced / O₂ consumed during respiration (1)\n• RQ for carbohydrate = 1.0 (equal amounts of CO₂ produced and O₂ consumed) (1)` },
      { q: 'Explain why the RQ for fats is less than 1.', marks: 2, markScheme: `• Fats have a lower proportion of oxygen relative to carbon and hydrogen in their structure (1)\n• More O₂ is needed to oxidise the carbon and hydrogen, but relatively less CO₂ is produced — so CO₂/O₂ < 1 (typically ~0.7) (1)` },
      { q: 'Describe the light-dependent reactions, including the role of photosystems I and II.', marks: 5, markScheme: `• Light energy is absorbed by photosystem II (PSII), exciting electrons to a higher energy level (photoionisation) (1)\n• Water is split (photolysis: 2H₂O → 4H⁺ + 4e⁻ + O₂) to replace lost electrons in PSII (1)\n• Excited electrons pass along an electron transport chain between PSII and PSI, releasing energy used to pump H⁺ into the thylakoid lumen — driving ATP synthesis via chemiosmosis (photophosphorylation) (1)\n• Electrons are re-excited by light in PSI and passed to NADP⁺ reductase (1)\n• NADP⁺ is reduced to NADPH using the electrons and H⁺ from photolysis (1)` },
      { q: 'Describe the Calvin cycle, including the role of RuBisCO.', marks: 5, markScheme: `• CO₂ is fixed by RuBisCO: CO₂ combines with ribulose bisphosphate (RuBP, 5C) to form 2 × glycerate-3-phosphate (GP, 3C) (1)\n• GP is reduced to triose phosphate (G3P) using ATP and reduced NADP from the light-dependent reactions (1)\n• Some G3P is used to synthesise glucose, amino acids, and lipids (1)\n• Most G3P (5/6) is used to regenerate RuBP, requiring ATP (1)\n• The cycle turns 6 times to produce 1 net glucose molecule (6 CO₂ fixed) (1)` },
      { q: 'Explain how light intensity affects the rate of photosynthesis, including the concept of the light compensation point.', marks: 4, markScheme: `• At low light intensity, the rate of photosynthesis increases proportionally with light intensity (light is the limiting factor) (1)\n• The light compensation point is where the rate of photosynthesis equals the rate of respiration (net gas exchange = 0) (1)\n• Above the compensation point, net photosynthesis exceeds respiration (net O₂ release) (1)\n• At high light intensity, the rate plateaus as another factor (CO₂ or temperature) becomes limiting (1)` },
      { q: 'Explain what is meant by net primary productivity (NPP) and how it relates to gross primary productivity (GPP).', marks: 3, markScheme: `• GPP = total energy/carbon fixed by photosynthesis in producers (1)\n• NPP = GPP − energy lost in plant respiration (R) (1)\n• NPP represents the energy available for growth of the plant and ultimately for consumers at the next trophic level (1)` },
      { q: 'Explain why food chains rarely have more than 4-5 trophic levels.', marks: 3, markScheme: `• Only ~10% of energy is transferred between each trophic level (1)\n• Energy is lost at each level through respiration (heat), excretion, egestion, and parts not consumed (1)\n• After 4-5 transfers, insufficient energy remains to support a viable population at the next level (1)` },
      { q: 'Describe how to measure gross primary productivity of an aquatic plant in a laboratory.', marks: 3, markScheme: `• Measure the rate of oxygen evolution in the light (= net photosynthesis) using an oxygen sensor or collecting gas (1)\n• Measure the rate of oxygen consumption in the dark (= respiration rate) (1)\n• GPP = net photosynthesis + respiration (add the two rates together) (1)` },
      { q: 'Define the terms population, community, and ecosystem.', marks: 3, markScheme: `• Population: all the organisms of one species in a particular area at a given time (1)\n• Community: all the populations of different species living and interacting in the same area (1)\n• Ecosystem: a community of organisms together with the abiotic (non-living) environment they interact with (1)` },
      { q: 'Describe the sigmoid (S-shaped) population growth curve and explain each phase.', marks: 4, markScheme: `• Lag phase: slow growth as population is small, organisms are acclimatising, few are reproducing (1)\n• Log/exponential phase: rapid growth as resources are abundant and there is little competition (1)\n• Stationary/plateau phase: population stabilises around the carrying capacity as birth rate ≈ death rate (1)\n• The carrying capacity is limited by density-dependent factors: intraspecific competition for food/space, predation, disease (1)` },
      { q: 'Explain what is meant by intraspecific and interspecific competition and give an example of each.', marks: 4, markScheme: `• Intraspecific: competition between individuals of the same species for the same resources (1)\n• Example: red deer stags competing for mates / trees of the same species competing for light (1)\n• Interspecific: competition between individuals of different species for shared resources (1)\n• Example: grey and red squirrels competing for food and habitat in the same woodland (1)` },
      { q: 'Describe how a quadrat and transect could be used to investigate the distribution of plant species across a habitat.', marks: 4, markScheme: `• Lay a transect (tape measure) across the area of interest, from one zone to another (e.g., shore to inland) (1)\n• Place quadrats at regular intervals (systematic sampling) or random points along the transect (1)\n• In each quadrat, record species present and estimate percentage cover or frequency (1)\n• Plot species distribution against distance along the transect to identify zonation patterns and correlate with abiotic factors (1)` },
      { q: 'Explain the assumptions and formula used in the mark-release-recapture method.', marks: 4, markScheme: `• Formula: N = (n₁ × n₂) / n_m where N = estimated population, n₁ = first capture, n₂ = second capture, n_m = marked recaptured (1)\n• Assumption 1: no births, deaths, immigration, or emigration between sampling events (1)\n• Assumption 2: marks do not affect survival or behaviour; marked individuals mix randomly with the population (1)\n• Assumption 3: marks are not lost or overlooked during recapture (1)` },
      { q: 'Explain how abiotic factors such as temperature and CO₂ concentration interact to limit photosynthesis.', marks: 3, markScheme: `• At low temperatures, enzymes (including RuBisCO) have low kinetic energy, reducing reaction rates even if light and CO₂ are adequate (1)\n• At low CO₂, RuBisCO cannot fix carbon fast enough even if light and temperature are optimal (1)\n• Only the factor in least supply limits the rate (principle of limiting factors); increasing it raises the rate until another factor becomes limiting (1)` },
      { q: 'Explain the role of reduced NAD and reduced FAD in aerobic respiration.', marks: 3, markScheme: `• They are coenzymes/hydrogen carriers that accept hydrogen atoms (electrons + protons) during glycolysis, the link reaction, and the Krebs cycle (1)\n• They carry these electrons to the electron transport chain on the inner mitochondrial membrane (1)\n• The electrons are passed along the chain, releasing energy used to generate most of the ATP via oxidative phosphorylation (1)` },
      { q: 'Explain what happens during anaerobic respiration in yeast (alcoholic fermentation).', marks: 3, markScheme: `• Glycolysis produces pyruvate, net 2 ATP, and reduced NAD (1)\n• Pyruvate is decarboxylated to ethanal (acetaldehyde), releasing CO₂ (1)\n• Ethanal is reduced to ethanol using hydrogen from reduced NAD, regenerating NAD so glycolysis can continue (1)` },
      { q: 'Explain why lactate production during anaerobic respiration in muscle must eventually be dealt with.', marks: 3, markScheme: `• Lactate accumulation lowers pH, which can inhibit enzyme activity and cause muscle fatigue (1)\n• Lactate must be transported to the liver via the blood where it is converted back to pyruvate (1)\n• Pyruvate can then be oxidised aerobically or converted to glucose/glycogen — this requires oxygen (oxygen debt) (1)` },
      { q: 'Describe the role of decomposers in recycling carbon in an ecosystem.', marks: 3, markScheme: `• Decomposers (bacteria, fungi) break down dead organic matter and waste by secreting enzymes and absorbing soluble products (1)\n• They respire the organic carbon compounds, releasing CO₂ back into the atmosphere (1)\n• This makes carbon available for re-uptake by producers via photosynthesis, completing the carbon cycle (1)` },
      { q: 'Explain what is meant by density-dependent factors affecting population growth.', marks: 2, markScheme: `• Density-dependent factors are those whose impact increases as population density increases (1)\n• Examples: competition for food/space, predation pressure, disease transmission — these act more strongly on larger populations and regulate population size around carrying capacity (1)` },
      { q: 'Explain what is meant by density-independent factors and give one example.', marks: 2, markScheme: `• Density-independent factors affect a population regardless of its size/density (1)\n• Example: natural disaster (flood, fire, drought), extreme weather event — kills a proportion of the population regardless of how many individuals exist (1)` },
      { q: 'Explain the difference between r-selected and K-selected species.', marks: 4, markScheme: `• r-selected: rapid reproduction, many small offspring, little parental care, short lifespan, early maturity — adapted to unstable environments (1)\n• K-selected: slow reproduction, few large offspring, high parental care, long lifespan, late maturity — adapted to stable environments near carrying capacity (1)\n• r-strategists exploit available resources quickly; K-strategists compete effectively in crowded environments (1)\n• Examples: r = bacteria, insects, rabbits; K = elephants, whales, humans (1)` },
      { q: 'Describe how a respirometer works and what it measures.', marks: 3, markScheme: `• An organism is sealed in a chamber connected to a capillary tube with a liquid indicator/manometer (1)\n• CO₂ is absorbed by KOH/soda lime, so only O₂ consumption causes a volume/pressure change (1)\n• The movement of liquid in the capillary measures the rate of O₂ uptake — a measure of aerobic metabolic rate (1)` },
      { q: 'Explain the significance of the proton gradient in both photosynthesis and respiration.', marks: 4, markScheme: `• In both processes, electron transport chains pump H⁺ ions across a membrane, creating a proton (electrochemical) gradient (1)\n• In photosynthesis: H⁺ accumulates in the thylakoid lumen and flows out through ATP synthase into the stroma (1)\n• In respiration: H⁺ accumulates in the intermembrane space and flows back into the matrix through ATP synthase (1)\n• In both cases, the flow of H⁺ down its gradient drives ATP synthase (chemiosmosis) to produce ATP — this is the fundamental mechanism of ATP generation (1)` },
      { q: 'Explain what is meant by the competitive exclusion principle.', marks: 2, markScheme: `• Two species competing for exactly the same resources/occupying the same niche cannot coexist indefinitely in the same habitat (1)\n• One species will outcompete the other, leading to local extinction of the inferior competitor or niche differentiation (1)` },
      { q: 'Explain how energy losses at each trophic level can be calculated.', marks: 3, markScheme: `• Energy input to a trophic level = energy consumed (ingested) by organisms at that level (1)\n• Energy lost = energy in faeces (egestion) + energy in excretory products + energy lost as heat from respiration (1)\n• Energy transferred to next level = energy assimilated into biomass (growth + reproduction) = ingested − (respiration + egestion + excretion) (1)` },
      { q: 'Explain how gross primary productivity could be estimated in a terrestrial ecosystem.', marks: 3, markScheme: `• Measure net primary productivity: harvest and dry plant biomass produced over a set time in a known area (1)\n• Estimate plant respiration: measure CO₂ release from plants in the dark or use accepted respiration values (1)\n• GPP = NPP + R (add plant respiration to net productivity) (1)` },
      { q: 'Explain the concept of ecological efficiency and why it matters for food production.', marks: 3, markScheme: `• Ecological efficiency = (energy transferred to next trophic level / energy available at previous level) × 100%; typically ~10% (1)\n• This means eating lower on the food chain (plants) is more energy-efficient than eating higher (meat) (1)\n• Understanding this helps design sustainable food systems — reducing trophic levels in food production reduces land, water, and energy requirements (1)` },
      { q: 'Describe how human activities disrupt the carbon cycle.', marks: 4, markScheme: `• Burning fossil fuels releases stored carbon as CO₂ into the atmosphere (1)\n• Deforestation reduces photosynthetic CO₂ absorption and releases stored carbon when trees decompose/burn (1)\n• These increase atmospheric CO₂ concentration, enhancing the greenhouse effect (1)\n• Cement production and land use changes also contribute — overall, carbon is being released faster than it can be sequestered (1)` },
      { q: 'Explain why the Calvin cycle depends on the light-dependent reactions.', marks: 3, markScheme: `• The Calvin cycle requires ATP (for reduction of GP to G3P and regeneration of RuBP) which is produced in the light-dependent reactions (1)\n• It requires reduced NADP (NADPH) as a reducing agent for the reduction of GP to G3P (1)\n• Without light, these products are not regenerated and the Calvin cycle cannot continue (1)` },
      { q: 'Explain what happens to the rate of photosynthesis when CO₂ concentration is increased at saturating light intensity.', marks: 3, markScheme: `• At saturating light, increasing CO₂ provides more substrate for RuBisCO in the Calvin cycle (1)\n• More GP is produced and reduced to G3P, increasing the rate of carbon fixation (1)\n• The rate increases until another factor becomes limiting (e.g., RuBisCO quantity, temperature for enzyme activity, light for ATP/NADPH supply) (1)` },
      { q: 'Explain why C4 plants have an advantage over C3 plants in hot, dry conditions.', marks: 4, markScheme: `• In hot/dry conditions, stomata close to reduce water loss, lowering internal CO₂ and raising O₂ (1)\n• C3 plants suffer photorespiration: RuBisCO fixes O₂ instead of CO₂, wasting energy (1)\n• C4 plants use PEP carboxylase (high affinity for CO₂) to initially fix CO₂ in mesophyll cells (1)\n• CO₂ is then concentrated in bundle sheath cells where the Calvin cycle occurs, reducing photorespiration and maintaining high rates of photosynthesis (1)` },
      { q: 'Explain how substrate-level phosphorylation differs from oxidative phosphorylation.', marks: 3, markScheme: `• Substrate-level phosphorylation: a phosphate group is transferred directly from a phosphorylated substrate to ADP, forming ATP — occurs in glycolysis and the Krebs cycle (1)\n• Oxidative phosphorylation: ATP is produced using energy from the electron transport chain and chemiosmosis on the inner mitochondrial membrane (1)\n• Oxidative phosphorylation produces the majority of ATP (~28-30 per glucose); substrate-level produces only a small amount (4 per glucose total) (1)` },
      { q: 'Describe how succession leads to a climax community.', marks: 4, markScheme: `• Pioneer species colonise bare substrate (e.g., lichens on rock), surviving harsh conditions and beginning soil formation (1)\n• They change the environment (soil depth, nutrient content, moisture retention), making it more suitable for other species (1)\n• A series of seral stages follow, with increasing biodiversity and biomass as conditions improve (1)\n• Eventually a climax community develops — a stable, self-sustaining community in dynamic equilibrium with the climate, with no further net change in species composition (1)` },
      { q: 'Explain the role of nitrogen-fixing bacteria in making nitrogen available to plants.', marks: 3, markScheme: `• Atmospheric N₂ is very stable (triple bond) and cannot be used directly by plants (1)\n• Nitrogen-fixing bacteria (e.g., Rhizobium in root nodules of legumes) use the enzyme nitrogenase to convert N₂ into ammonia (NH₃)/ammonium (NH₄⁺) (1)\n• Ammonium can then be converted to nitrate by nitrifying bacteria, which plants absorb through their roots for amino acid/protein synthesis (1)` },
      { q: 'Explain how predator-prey interactions can lead to population oscillations.', marks: 3, markScheme: `• When prey numbers are high, predators have abundant food and their population increases (1)\n• Increased predation reduces prey numbers (1)\n• With fewer prey, predators decline due to starvation/reduced reproduction — prey then recover, and the cycle repeats with a time lag (1)` },
      { q: 'Explain why deforestation can lead to soil erosion and nutrient loss.', marks: 3, markScheme: `• Trees and roots hold soil in place and reduce the impact of rainfall — their removal exposes soil to wind and water erosion (1)\n• The nutrient cycle is disrupted: without trees absorbing nutrients, minerals are washed out of the soil by rain (leaching) (1)\n• Decomposition of remaining organic matter without replacement by leaf litter further depletes soil nutrients (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── B5 */
  'B5': {
    name: 'Genetics, Control and Homeostasis',
    questions: [
      { q: 'State what is meant by the term "allele".', marks: 1, markScheme: `• A different version/variant of a gene (at the same locus on a chromosome) (1)` },
      { q: 'State the difference between homozygous and heterozygous.', marks: 2, markScheme: `• Homozygous: two identical alleles for a gene (e.g., AA or aa) (1)\n• Heterozygous: two different alleles for a gene (e.g., Aa) (1)` },
      { q: 'State what is meant by "codominance".', marks: 2, markScheme: `• Both alleles are fully expressed in the phenotype of a heterozygote (1)\n• Neither allele is dominant over the other — e.g., in blood group AB, both A and B antigens are expressed (1)` },
      { q: 'State what is meant by "homeostasis".', marks: 2, markScheme: `• The maintenance of a constant/stable internal environment (1)\n• Despite external changes, conditions are kept within a narrow range around a set point (1)` },
      { q: 'State the role of insulin in blood glucose regulation.', marks: 2, markScheme: `• Insulin is released by β-cells of the pancreas when blood glucose is high (1)\n• It causes cells to take up glucose (via GLUT4 transporters) and stimulates the liver to convert glucose to glycogen (glycogenesis), lowering blood glucose (1)` },
      { q: 'State the role of glucagon in blood glucose regulation.', marks: 2, markScheme: `• Glucagon is released by α-cells of the pancreas when blood glucose is low (1)\n• It stimulates the liver to break down glycogen to glucose (glycogenolysis) and promote gluconeogenesis, raising blood glucose (1)` },
      { q: 'Describe the structure of a myelinated motor neurone.', marks: 3, markScheme: `• Cell body containing the nucleus, with dendrites for receiving impulses (1)\n• Long axon carrying impulses away from the cell body to the effector (1)\n• Myelin sheath (Schwann cells) insulates the axon with gaps (nodes of Ranvier) for saltatory conduction (1)` },
      { q: 'State what is meant by resting potential and its typical value.', marks: 2, markScheme: `• Resting potential is the voltage difference across the membrane of a neurone when not transmitting an impulse (1)\n• Typically about −70 mV (inside is negative relative to outside), maintained by the Na⁺/K⁺ pump and K⁺ leak channels (1)` },
      { q: 'Describe how an action potential is generated.', marks: 4, markScheme: `• A stimulus causes voltage-gated Na⁺ channels to open (1)\n• Na⁺ ions rush into the axon (down their electrochemical gradient), depolarising the membrane to about +40 mV (1)\n• Na⁺ channels inactivate; voltage-gated K⁺ channels open, K⁺ moves out, causing repolarisation (1)\n• Brief hyperpolarisation occurs before the resting potential is restored by the Na⁺/K⁺ pump (1)` },
      { q: 'Explain what is meant by saltatory conduction and why it is faster.', marks: 3, markScheme: `• In myelinated neurones, the myelin sheath insulates the axon and prevents ion exchange (1)\n• Action potentials can only occur at the nodes of Ranvier (gaps in the myelin) (1)\n• The impulse "jumps" from node to node, greatly increasing the speed of conduction compared to continuous propagation in unmyelinated neurones (1)` },
      { q: 'Describe how a nerve impulse is transmitted across a synapse.', marks: 5, markScheme: `• Action potential arrives at the presynaptic membrane (1)\n• Voltage-gated Ca²⁺ channels open; Ca²⁺ enters the presynaptic knob (1)\n• Ca²⁺ causes synaptic vesicles (containing neurotransmitter, e.g., acetylcholine) to fuse with the presynaptic membrane and release neurotransmitter into the synaptic cleft (exocytosis) (1)\n• Neurotransmitter diffuses across the cleft and binds to specific receptors on the postsynaptic membrane (1)\n• This opens ion channels (e.g., Na⁺), causing depolarisation of the postsynaptic neurone — if threshold is reached, a new action potential is generated (1)` },
      { q: 'Explain negative feedback in the regulation of blood glucose, including the roles of the pancreas and liver.', marks: 5, markScheme: `• High blood glucose: detected by β-cells of the pancreas, which secrete insulin (1)\n• Insulin stimulates glucose uptake by cells (muscle, adipose) and glycogenesis in the liver — blood glucose falls (1)\n• Low blood glucose: detected by α-cells, which secrete glucagon (1)\n• Glucagon stimulates glycogenolysis and gluconeogenesis in the liver — blood glucose rises (1)\n• This is negative feedback: the response counteracts the change, returning glucose to the set point (1)` },
      { q: 'Explain the difference between Type 1 and Type 2 diabetes.', marks: 4, markScheme: `• Type 1: autoimmune destruction of β-cells; little or no insulin is produced; usually early onset; treated with insulin injections (1)\n• Type 2: cells become resistant to insulin and/or β-cells produce insufficient insulin; often linked to obesity/lifestyle; later onset (1)\n• Type 1 is not preventable; Type 2 can often be managed/prevented with diet and exercise (1)\n• Both result in poorly controlled blood glucose — hyperglycaemia and associated complications (1)` },
      { q: 'Describe the role of the hypothalamus in thermoregulation.', marks: 4, markScheme: `• The hypothalamus acts as the thermoregulatory centre, receiving input from thermoreceptors in the skin (peripheral) and in the blood (central) (1)\n• If core temperature is too high: hypothalamus triggers vasodilation, sweating, and reduced metabolic rate (1)\n• If core temperature is too low: hypothalamus triggers vasoconstriction, shivering, and increased metabolic rate (1)\n• These are negative feedback responses — the effectors counteract the change to return temperature to 37°C (1)` },
      { q: 'Explain the role of ADH in osmoregulation.', marks: 4, markScheme: `• Osmoreceptors in the hypothalamus detect a decrease in blood water potential (increased solute concentration) (1)\n• The posterior pituitary gland releases more ADH into the blood (1)\n• ADH binds to receptors on collecting duct cells in the kidney, stimulating the insertion of aquaporin water channels (1)\n• This increases water reabsorption by osmosis from the filtrate back into the blood, producing concentrated urine — negative feedback returns water potential to normal (1)` },
      { q: 'Describe the process of transcription.', marks: 4, markScheme: `• RNA polymerase binds to the promoter region of the gene on the template strand of DNA (1)\n• The DNA unwinds and RNA polymerase synthesises a complementary mRNA strand in the 5′→3′ direction (1)\n• RNA nucleotides are added by complementary base pairing (A→U, T→A, C→G, G→C) (1)\n• Transcription continues until a terminator sequence is reached; the pre-mRNA is then processed (splicing, capping, polyadenylation) before leaving the nucleus (1)` },
      { q: 'Describe the process of translation at a ribosome.', marks: 5, markScheme: `• mRNA binds to a ribosome; the start codon (AUG) is positioned in the first site (1)\n• A tRNA with the complementary anticodon brings the corresponding amino acid (methionine) to the ribosome (1)\n• A second tRNA brings the next amino acid; a peptide bond forms between adjacent amino acids (catalysed by the ribosome/peptidyl transferase) (1)\n• The ribosome moves along the mRNA one codon at a time (translocation); the first tRNA is released (1)\n• This continues until a stop codon is reached — no tRNA has a complementary anticodon, so a release factor causes the polypeptide to be released (1)` },
      { q: 'Explain what is meant by epistasis and give an example.', marks: 3, markScheme: `• Epistasis is a gene interaction where one gene masks or modifies the expression of a different gene at a separate locus (1)\n• The gene that masks is called the epistatic gene; the gene being masked is the hypostatic gene (1)\n• Example: coat colour in Labrador dogs — the E gene controls pigment deposition; ee prevents any pigment from being deposited regardless of the B gene genotype (1)` },
      { q: 'Explain how you would use a chi-squared test to analyse the results of a dihybrid cross.', marks: 4, markScheme: `• State a null hypothesis: observed ratios do not differ significantly from expected (e.g., 9:3:3:1) (1)\n• Calculate expected numbers for each phenotype class based on the expected ratio and total count (1)\n• Calculate χ² = Σ[(O−E)²/E] for all categories (1)\n• Compare χ² with the critical value at p=0.05 with appropriate degrees of freedom (number of categories − 1); if χ² < critical value, accept H₀ (observed fits expected ratio) (1)` },
      { q: 'Explain the Hardy-Weinberg principle and state the conditions required for equilibrium.', marks: 4, markScheme: `• The Hardy-Weinberg principle states that allele and genotype frequencies remain constant from generation to generation in a population that is in genetic equilibrium (1)\n• Equations: p + q = 1 (allele frequencies); p² + 2pq + q² = 1 (genotype frequencies) (1)\n• Conditions: no natural selection, no mutation, no migration (gene flow), random mating, large population size (no genetic drift) (1)\n• Departure from equilibrium indicates that one or more evolutionary forces are acting (1)` },
      { q: 'Explain what is meant by "gene linkage" and how it affects expected ratios in a dihybrid cross.', marks: 3, markScheme: `• Linked genes are located on the same chromosome and tend to be inherited together (1)\n• This means they do not assort independently during meiosis — deviating from the expected 9:3:3:1 ratio (1)\n• Recombination (crossing over) can separate linked genes, but recombinant phenotypes appear at lower frequency than expected (1)` },
      { q: 'Explain how the sympathetic and parasympathetic nervous systems work antagonistically to control heart rate.', marks: 4, markScheme: `• The medulla oblongata contains the cardiovascular centre (1)\n• Sympathetic nerve (accelerator nerve) releases noradrenaline at the SAN, increasing heart rate (during exercise/stress) (1)\n• Parasympathetic nerve (vagus nerve) releases acetylcholine at the SAN, decreasing heart rate (at rest) (1)\n• They work antagonistically: increasing activity of one system while decreasing the other allows fine control of heart rate (1)` },
      { q: 'Explain how baroreceptors and chemoreceptors contribute to heart rate regulation.', marks: 4, markScheme: `• Baroreceptors (in the aortic arch and carotid sinus) detect changes in blood pressure (1)\n• High blood pressure: baroreceptors send more impulses to medulla, which increases parasympathetic output to slow heart rate (1)\n• Chemoreceptors (in the aortic and carotid bodies) detect changes in blood CO₂, pH, and O₂ (1)\n• High CO₂/low pH during exercise: chemoreceptors stimulate the medulla to increase sympathetic output, raising heart rate and cardiac output to meet demand (1)` },
      { q: 'Describe how gibberellins promote seed germination.', marks: 3, markScheme: `• When a seed imbibes water, the embryo produces gibberellins (1)\n• Gibberellins diffuse to the aleurone layer, stimulating the production of amylase (and other hydrolytic enzymes) (1)\n• Amylase breaks down starch in the endosperm into maltose/glucose, providing a respiratory substrate for the growing embryo (1)` },
      { q: 'Describe the main steps in PCR (polymerase chain reaction).', marks: 4, markScheme: `• Denaturation (~95°C): DNA strands separate as hydrogen bonds between base pairs break (1)\n• Annealing (~50-65°C): short DNA primers bind (anneal) to complementary sequences flanking the target region (1)\n• Extension (~72°C): heat-stable DNA polymerase (Taq polymerase) extends the primers, synthesising new complementary strands (1)\n• The cycle is repeated 25-30 times, exponentially amplifying the target DNA sequence (2ⁿ copies after n cycles) (1)` },
      { q: 'Describe how restriction enzymes and DNA ligase are used in genetic engineering.', marks: 3, markScheme: `• Restriction enzymes cut DNA at specific palindromic recognition sequences, often producing sticky ends (short single-stranded overhangs) (1)\n• The same restriction enzyme is used to cut both the target gene and the vector (plasmid), creating complementary sticky ends (1)\n• DNA ligase joins the fragments by forming phosphodiester bonds between the sugar-phosphate backbones, sealing the recombinant DNA (1)` },
      { q: 'Explain how gel electrophoresis separates DNA fragments.', marks: 3, markScheme: `• DNA fragments are loaded into wells in an agarose gel and an electric field is applied (1)\n• DNA is negatively charged (phosphate groups), so fragments migrate toward the positive electrode (anode) (1)\n• Smaller fragments move faster/further through the gel pores than larger ones — separating fragments by size (1)` },
      { q: 'Explain what is meant by "epigenetics" and give one example of an epigenetic modification.', marks: 3, markScheme: `• Epigenetics refers to heritable changes in gene expression that do not involve changes to the DNA base sequence (1)\n• These modifications affect whether genes are "switched on or off" in different cell types (1)\n• Example: DNA methylation — addition of methyl groups to cytosine bases in promoter regions can silence gene transcription (1)` },
      { q: 'Explain how natural selection can lead to a change in allele frequency in a population over time.', marks: 4, markScheme: `• Genetic variation exists within a population due to mutation and sexual reproduction (1)\n• Individuals with phenotypes better suited to the environment have a selective advantage — they are more likely to survive and reproduce (1)\n• These individuals pass on their advantageous alleles to the next generation at a higher frequency (1)\n• Over many generations, the frequency of the advantageous allele increases in the population while less favourable alleles decrease (1)` },
      { q: 'Explain what is meant by "genetic drift" and when it is most significant.', marks: 3, markScheme: `• Genetic drift is the random change in allele frequency due to chance events, not natural selection (1)\n• It is most significant in small populations, where chance events can have a large effect on allele frequencies (1)\n• Examples include the founder effect (small group colonises new area) and population bottleneck (drastic population reduction) — both reduce genetic diversity (1)` },
      { q: 'Explain why maintaining genetic diversity is important for the long-term survival of a species.', marks: 3, markScheme: `• Genetic diversity provides a range of alleles within the population (1)\n• This increases the probability that some individuals possess alleles conferring resistance to new diseases, changing environments, or other selection pressures (1)\n• Without genetic diversity, a population may be unable to adapt and could face extinction (1)` },
      { q: 'Explain how the structure of a nephron relates to its function in ultrafiltration.', marks: 3, markScheme: `• The afferent arteriole is wider than the efferent arteriole, creating high hydrostatic pressure in the glomerular capillaries (1)\n• The basement membrane and podocytes of Bowman\'s capsule act as a filter — allowing small molecules (water, glucose, ions, urea) through but retaining large molecules (proteins, blood cells) (1)\n• The filtrate collects in Bowman\'s capsule and passes into the proximal convoluted tubule for selective reabsorption (1)` },
      { q: 'Explain how selective reabsorption occurs in the proximal convoluted tubule.', marks: 4, markScheme: `• The PCT has microvilli (brush border) increasing surface area for reabsorption (1)\n• Many mitochondria provide ATP for active transport of glucose, amino acids, and ions out of the filtrate (1)\n• Na⁺ is actively pumped out at the basal membrane; glucose is co-transported with Na⁺ at the apical membrane (1)\n• Water follows by osmosis due to the solute gradient created; ~65% of filtrate is reabsorbed in the PCT (1)` },
      { q: 'Explain the countercurrent multiplier mechanism in the loop of Henle.', marks: 4, markScheme: `• The descending limb is permeable to water but not to ions — water leaves by osmosis into the hypertonic medulla, concentrating the filtrate (1)\n• The ascending limb is impermeable to water but actively pumps Na⁺/Cl⁻ out into the medulla (1)\n• This creates and maintains a salt concentration gradient in the medulla (increasing towards the inner medulla) (1)\n• The countercurrent flow (opposite directions in descending and ascending limbs) maximises the efficiency of this gradient (1)` },
      { q: 'Compare nervous and hormonal communication.', marks: 4, markScheme: `• Nervous: fast transmission (electrical impulses along neurones), short-lived response, highly localised/targeted (1)\n• Hormonal: slower (chemicals carried in blood), longer-lasting effects, widespread but only affects target cells with specific receptors (1)\n• Nervous uses electrical signals and neurotransmitters at synapses; hormonal uses chemical messengers (hormones) in the blood (1)\n• Both are coordinated by the hypothalamus and use negative feedback; the nervous system provides rapid responses while hormones control longer-term processes (1)` },
      { q: 'Explain the role of transcription factors in regulating gene expression.', marks: 3, markScheme: `• Transcription factors are proteins that bind to specific DNA sequences (promoters/enhancers) near a gene (1)\n• Activators enhance transcription by helping RNA polymerase bind to the promoter (1)\n• Repressors inhibit transcription by blocking RNA polymerase or condensing chromatin — this allows different genes to be expressed in different cell types from the same genome (1)` },
      { q: 'Explain how a reflex arc provides a rapid response to a stimulus.', marks: 4, markScheme: `• Receptor detects the stimulus and generates a nerve impulse (1)\n• Sensory neurone transmits the impulse to the CNS (spinal cord) (1)\n• Relay neurone in the spinal cord passes the impulse directly to a motor neurone (few synapses = fast) (1)\n• Motor neurone carries the impulse to the effector (muscle/gland), which produces the response — the pathway is short and involuntary, allowing a rapid protective response (1)` },
      { q: 'Explain what is meant by a "test cross" and when it is useful.', marks: 3, markScheme: `• A test cross involves crossing an individual with the dominant phenotype with a homozygous recessive individual (1)\n• It is used to determine whether the dominant individual is homozygous (AA) or heterozygous (Aa) (1)\n• If any offspring show the recessive phenotype, the individual must be heterozygous; if all offspring are dominant, it is likely homozygous (1)` },
      { q: 'Explain how sex-linked inheritance differs from autosomal inheritance using an X-linked recessive example.', marks: 4, markScheme: `• Sex-linked genes are located on the X chromosome; males (XY) have only one copy while females (XX) have two (1)\n• Males are more likely to express X-linked recessive conditions because they have no second X allele to mask it (1)\n• Females can be carriers (heterozygous) — they carry the allele but do not express the condition (1)\n• Example: haemophilia — affected males (X^h Y) inherit the allele from a carrier mother; affected females (X^h X^h) are rare as they need two copies (1)` },
      { q: 'Explain why different cells in an organism express different genes despite having identical DNA.', marks: 3, markScheme: `• All body cells contain the same DNA (genome) but gene expression is regulated differently in each cell type (1)\n• Transcription factors, epigenetic modifications (methylation, histone modification), and signalling molecules determine which genes are active (1)\n• This differential gene expression allows cells to produce different proteins, resulting in different structures and functions (differentiation) (1)` },
      { q: 'Explain how a change in one amino acid can affect protein function, using sickle cell haemoglobin as an example.', marks: 4, markScheme: `• A point mutation (GAG→GTG in DNA) changes one codon, replacing glutamic acid with valine at position 6 of the β-globin chain (1)\n• Valine is hydrophobic (glutamic acid is hydrophilic), causing haemoglobin S molecules to polymerise under low O₂ conditions (1)\n• Polymerisation distorts red blood cells into a sickle shape, blocking capillaries and reducing O₂ delivery (1)\n• This demonstrates how primary structure determines tertiary/quaternary structure and ultimately function (1)` },
      { q: 'Explain how continuous variation differs from discontinuous variation.', marks: 3, markScheme: `• Continuous variation: phenotype shows a range of values with no distinct categories (e.g., height, mass) — usually polygenic and influenced by the environment (1)\n• Discontinuous variation: phenotype falls into distinct categories with no intermediates (e.g., blood group, tongue rolling) — usually controlled by one or few genes with little environmental influence (1)\n• Continuous variation gives a normal distribution curve; discontinuous gives a bar chart with separate categories (1)` },
      { q: 'Explain the role of the autonomic nervous system in the "fight or flight" response.', marks: 4, markScheme: `• The sympathetic division of the autonomic nervous system is activated during stress/danger (1)\n• It stimulates the adrenal medulla to release adrenaline into the blood (1)\n• Effects: increased heart rate, bronchiole dilation, glycogen→glucose conversion in liver, blood redirected to muscles (1)\n• The parasympathetic division is inhibited during this response and restores resting conditions afterwards (1)` },
      { q: 'Explain what is meant by "multiple alleles" using the ABO blood group system as an example.', marks: 4, markScheme: `• Multiple alleles means more than two alleles exist for a single gene in the population (though each individual still carries only two) (1)\n• ABO blood group: three alleles — I^A, I^B, and i (1)\n• I^A and I^B are codominant to each other (AB phenotype when both present); both are dominant to i (1)\n• This gives six possible genotypes and four phenotypes: A (I^A I^A or I^A i), B (I^B I^B or I^B i), AB (I^A I^B), O (ii) (1)` },
    ],
  },

  /* ─────────────────────────────────────────────────────────── B6 */
  'B6': {
    name: 'Biotechnology, Ecosystems and Human Impact',
    questions: [
      { q: 'State what is meant by "genetic engineering".', marks: 1, markScheme: `• The deliberate modification of an organism\'s genome by inserting, deleting, or altering specific genes using biotechnology techniques (1)` },
      { q: 'State the role of a vector in genetic engineering.', marks: 1, markScheme: `• A vector (e.g., plasmid, virus) carries the desired gene into the host cell (1)` },
      { q: 'State what is meant by "biodiversity".', marks: 1, markScheme: `• The variety of living organisms in an area, at all levels: genetic, species, and ecosystem diversity (1)` },
      { q: 'State the difference between primary and secondary succession.', marks: 2, markScheme: `• Primary succession starts on bare/lifeless substrate (e.g., bare rock, lava) where no soil exists (1)\n• Secondary succession starts on previously colonised land after disturbance (e.g., fire, flood) where soil is already present (1)` },
      { q: 'State what is meant by a "climax community".', marks: 2, markScheme: `• A climax community is the final, stable stage of succession (1)\n• It is in dynamic equilibrium with the environment — species composition remains relatively constant (1)` },
      { q: 'Describe the role of restriction enzymes in genetic engineering.', marks: 2, markScheme: `• Restriction enzymes cut DNA at specific recognition sequences (palindromic sequences) (1)\n• They often produce sticky ends — short single-stranded overhangs that can base-pair with complementary sticky ends from another DNA source (1)` },
      { q: 'Describe the role of DNA ligase in genetic engineering.', marks: 2, markScheme: `• DNA ligase joins DNA fragments together by forming phosphodiester bonds (1)\n• It seals the sugar-phosphate backbone between the inserted gene and the vector DNA (1)` },
      { q: 'Describe how transformation is achieved in bacteria.', marks: 2, markScheme: `• The recombinant plasmid is introduced into bacterial cells (1)\n• Methods include heat shock (CaCl₂ treatment then brief exposure to 42°C) or electroporation (brief electrical pulse makes membrane permeable) (1)` },
      { q: 'Explain the role of marker genes in genetic engineering.', marks: 3, markScheme: `• Not all bacterial cells will take up the recombinant plasmid — marker genes allow identification of successful transformants (1)\n• Example: antibiotic resistance gene — cells are grown on agar containing the antibiotic (1)\n• Only cells that have taken up the plasmid (containing the resistance gene) will survive and grow — others die (1)` },
      { q: 'Describe the process of gel electrophoresis for separating DNA fragments.', marks: 4, markScheme: `• DNA is cut into fragments using restriction enzymes (1)\n• Fragments are loaded into wells in an agarose gel and an electric current is applied (1)\n• DNA (negatively charged) moves toward the positive electrode; smaller fragments travel further (1)\n• Fragments are visualised using UV light after staining (e.g., ethidium bromide) or radioactive/fluorescent probes (1)` },
      { q: 'Describe how DNA profiling works and state one application.', marks: 4, markScheme: `• DNA is extracted and specific regions containing variable number tandem repeats (VNTRs/STRs) are amplified by PCR (1)\n• Amplified fragments are separated by gel electrophoresis (1)\n• The pattern of bands is unique to each individual (except identical twins) — creating a "DNA fingerprint" (1)\n• Application: forensic identification / paternity testing / identifying genetic relationships between organisms (1)` },
      { q: 'Describe the carbon cycle, including the roles of photosynthesis, respiration, and combustion.', marks: 4, markScheme: `• Photosynthesis removes CO₂ from the atmosphere, fixing it into organic molecules (glucose) in producers (1)\n• Respiration (by all living organisms) releases CO₂ back into the atmosphere by oxidising organic molecules (1)\n• Decomposition: decomposers break down dead organic matter, releasing CO₂ through their respiration (1)\n• Combustion: burning fossil fuels (and biomass) rapidly releases stored carbon as CO₂ into the atmosphere (1)` },
      { q: 'Describe the nitrogen cycle, including fixation, nitrification, and denitrification.', marks: 5, markScheme: `• Nitrogen fixation: N₂ → NH₃/NH₄⁺ by nitrogen-fixing bacteria (Rhizobium in root nodules, or free-living Azotobacter) (1)\n• Ammonification: decomposers convert organic nitrogen (proteins) in dead matter into ammonia/ammonium (1)\n• Nitrification: nitrifying bacteria oxidise NH₄⁺ → NO₂⁻ (Nitrosomonas) → NO₃⁻ (Nitrobacter) in aerobic conditions (1)\n• Assimilation: plants absorb NO₃⁻ through roots for amino acid/protein synthesis (1)\n• Denitrification: denitrifying bacteria (anaerobic) convert NO₃⁻ → N₂ gas, returning nitrogen to the atmosphere (1)` },
      { q: 'Explain the process of eutrophication.', marks: 4, markScheme: `• Excess inorganic fertilisers (nitrates, phosphates) are leached from farmland into waterways (1)\n• Nutrients stimulate excessive algal growth (algal bloom) on the surface (1)\n• The algal bloom blocks light to submerged plants, which die; when algae also die, they increase dead organic matter (1)\n• Aerobic decomposers multiply, consuming dissolved oxygen (high BOD) — oxygen depletion causes death of aerobic aquatic organisms (fish, invertebrates) (1)` },
      { q: 'Explain how deforestation contributes to increased atmospheric CO₂ and reduced biodiversity.', marks: 4, markScheme: `• Fewer trees means less photosynthetic CO₂ absorption (1)\n• Burning or decomposition of felled trees releases stored carbon as CO₂ (1)\n• Habitat destruction removes the environment for many species — leading to local/global extinction (1)\n• Loss of biodiversity reduces ecosystem resilience and the gene pool available for adaptation (1)` },
      { q: 'Explain the enhanced greenhouse effect and its link to human activities.', marks: 4, markScheme: `• Greenhouse gases (CO₂, methane, N₂O) trap infrared radiation re-emitted by the Earth\'s surface, warming the atmosphere (1)\n• Human activities (burning fossil fuels, deforestation, intensive farming) increase concentrations of these gases beyond natural levels (1)\n• This enhances the greenhouse effect, causing global temperatures to rise (global warming) (1)\n• Consequences include sea level rise, changing weather patterns, habitat loss, and altered species distributions (1)` },
      { q: 'Describe how Simpson\'s Index of Diversity is calculated and interpret a result.', marks: 3, markScheme: `• D = 1 − Σ(n/N)² where n = number of individuals of each species, N = total number of individuals (1)\n• D ranges from 0 to 1; values closer to 1 indicate higher diversity (1)\n• The index accounts for both species richness and evenness — two communities with the same number of species but different evenness will have different D values (1)` },
      { q: 'Describe how quadrats can be used to estimate plant species diversity in a field.', marks: 3, markScheme: `• Place quadrats randomly (using random number coordinates) throughout the field to avoid bias (1)\n• In each quadrat, identify and count the number of individuals of each species (or estimate percentage cover) (1)\n• Use data from all quadrats to calculate species richness, frequency, and Simpson\'s Index of Diversity (1)` },
      { q: 'Explain why maintaining biodiversity is important for ecosystem stability.', marks: 3, markScheme: `• Greater biodiversity provides more food web connections — if one species declines, others can compensate (redundancy) (1)\n• Diverse ecosystems are more resilient to environmental change and can recover more quickly from disturbance (1)\n• Biodiversity provides ecosystem services: pollination, nutrient cycling, water purification, carbon sequestration (1)` },
      { q: 'Explain what is meant by "conservation" and describe one in-situ conservation method.', marks: 3, markScheme: `• Conservation is the management and protection of biodiversity and natural habitats for sustainable use (1)\n• In-situ method: nature reserves / national parks — protecting habitats in their natural location (1)\n• This allows organisms to continue evolving in their natural environment, maintaining ecological relationships and genetic diversity (1)` },
      { q: 'Explain one advantage and one disadvantage of ex-situ conservation (e.g., zoos, seed banks).', marks: 2, markScheme: `• Advantage: protects species from immediate extinction when habitat is destroyed; captive breeding programmes can increase population size (1)\n• Disadvantage: limited genetic diversity (small populations), animals may lose natural behaviours, expensive to maintain, and does not protect the habitat itself (1)` },
      { q: 'Describe how CRISPR-Cas9 can be used to edit genes.', marks: 4, markScheme: `• A guide RNA (gRNA) is designed to be complementary to the target DNA sequence (1)\n• The gRNA directs the Cas9 nuclease enzyme to the specific location in the genome (1)\n• Cas9 makes a double-stranded cut in the DNA at the target site (1)\n• The cell\'s DNA repair mechanisms can then delete the gene (NHEJ) or insert a new sequence (HDR with a template) (1)` },
      { q: 'Explain the role of microorganisms in bioremediation.', marks: 3, markScheme: `• Specific microorganisms are used to break down/metabolise pollutants in contaminated environments (1)\n• Example: bacteria that degrade oil hydrocarbons are used to clean up oil spills (1)\n• Advantages: less damaging than chemical treatments, can be targeted, and is often more cost-effective for large-scale contamination (1)` },
      { q: 'Describe how fermenters (bioreactors) are used in biotechnology.', marks: 4, markScheme: `• Microorganisms are grown in large, sterile vessels under carefully controlled conditions (1)\n• Conditions controlled: temperature, pH, oxygen supply, nutrient concentration — to optimise growth and product yield (1)\n• Aseptic technique prevents contamination by unwanted organisms (1)\n• Products are harvested downstream: e.g., antibiotics (Penicillium), insulin (recombinant E. coli), single-cell protein (Fusarium) (1)` },
      { q: 'Explain why antibiotic resistance is a growing global health concern.', marks: 4, markScheme: `• Overuse and misuse of antibiotics (in medicine and agriculture) creates selection pressure favouring resistant bacteria (1)\n• Resistant bacteria survive, reproduce, and spread resistance genes (including via horizontal gene transfer on plasmids) (1)\n• Multi-drug resistant strains (e.g., MRSA) are increasingly difficult/impossible to treat with existing antibiotics (1)\n• This threatens routine medical procedures (surgery, chemotherapy) that rely on effective antibiotics to prevent infection (1)` },
      { q: 'Describe how biological control works and state one advantage over chemical pest control.', marks: 3, markScheme: `• A natural predator, parasite, or pathogen of the pest is introduced to reduce pest population (1)\n• Example: ladybirds to control aphids, or Bt bacteria to kill caterpillars (1)\n• Advantage: more sustainable / does not pollute / pest does not easily develop resistance / self-sustaining once established (1)` },
      { q: 'Explain how intensive farming practices can reduce biodiversity.', marks: 3, markScheme: `• Monocultures reduce plant diversity and the habitats available for other organisms (1)\n• Pesticides kill non-target organisms (insects, plants) and reduce food availability for higher trophic levels (1)\n• Removal of hedgerows/field margins destroys habitats for birds, mammals, and invertebrates (1)` },
      { q: 'Explain the role of saprotrophic microorganisms in nutrient cycling.', marks: 3, markScheme: `• Saprotrophs (fungi and bacteria) feed on dead organic matter (1)\n• They secrete extracellular enzymes that digest complex organic molecules into simpler soluble ones, which they then absorb (1)\n• This releases inorganic nutrients (e.g., NH₄⁺, NO₃⁻, PO₄³⁻) back into the soil, making them available for plant uptake — completing nutrient cycles (1)` },
      { q: 'Describe the impact of pesticide accumulation (bioaccumulation and biomagnification) on food chains.', marks: 4, markScheme: `• Bioaccumulation: persistent pesticides (e.g., DDT) are not broken down and accumulate in the fatty tissues of organisms over time (1)\n• Biomagnification: concentration increases at each successive trophic level because predators consume many contaminated prey organisms (1)\n• Top predators accumulate the highest concentrations, potentially reaching toxic levels (1)\n• Example: DDT caused eggshell thinning in birds of prey (e.g., peregrine falcons), reducing reproductive success (1)` },
      { q: 'Explain why international cooperation is needed to address climate change.', marks: 3, markScheme: `• Climate change is a global problem — greenhouse gases emitted in one country affect the whole planet (1)\n• Individual nations acting alone cannot solve the problem; coordinated emission reductions are needed (1)\n• International agreements (e.g., Paris Agreement) set shared targets, promote technology transfer to developing nations, and create accountability mechanisms (1)` },
      { q: 'Describe one application of genetic engineering in medicine.', marks: 3, markScheme: `• Production of human insulin: the human insulin gene is inserted into E. coli bacteria using a plasmid vector (1)\n• The bacteria are cultured in fermenters, expressing and producing human insulin on a large scale (1)\n• This provides a reliable, pure supply of insulin for treating diabetes without relying on animal sources (fewer allergic reactions, ethically more acceptable) (1)` },
      { q: 'Explain the concept of "food miles" and its relationship to carbon footprint.', marks: 2, markScheme: `• Food miles is the distance food is transported from producer to consumer (1)\n• Greater food miles generally means more fossil fuel burned for transportation, increasing CO₂ emissions and the carbon footprint of the food (1)` },
      { q: 'Explain how the loss of a keystone species can affect an entire ecosystem.', marks: 3, markScheme: `• A keystone species has a disproportionately large effect on its environment relative to its abundance (e.g., top predator, ecosystem engineer) (1)\n• Its removal triggers cascading effects through the food web — e.g., herbivore populations may explode, overgrazing vegetation (1)\n• This trophic cascade can lead to loss of other species, habitat degradation, and reduced overall biodiversity (1)` },
      { q: 'Describe one ethical argument for and one against the use of animals in medical research.', marks: 2, markScheme: `• For: animal testing has led to life-saving treatments and vaccines; it may be necessary when no alternatives exist to ensure human safety (1)\n• Against: animals suffer pain/distress and cannot give consent; some argue animals have intrinsic rights that should not be violated for human benefit (1)` },
      { q: 'Explain how selective breeding can reduce genetic diversity and why this is a concern.', marks: 3, markScheme: `• Selective breeding involves repeatedly crossing individuals with desired traits, narrowing the gene pool over generations (1)\n• This reduces genetic diversity — many alleles are lost from the breeding population (1)\n• Reduced diversity makes the population vulnerable to disease or environmental change, as fewer alleles may confer resistance (inbreeding depression may also reduce fitness) (1)` },
      { q: 'Explain the advantages of using microorganisms for food production (e.g., Quorn/mycoprotein).', marks: 3, markScheme: `• Microorganisms (e.g., Fusarium venenatum for Quorn) grow rapidly and can be produced year-round in fermenters independent of climate (1)\n• They can use waste products as substrate and require less land and water than livestock farming (1)\n• Production has a lower carbon footprint and does not require animal slaughter — addressing environmental and ethical concerns (1)` },
      { q: 'Describe the role of pioneer species in primary succession.', marks: 3, markScheme: `• Pioneer species (e.g., lichens, mosses) are the first organisms to colonise bare, inhospitable substrate (1)\n• They can survive harsh conditions (little soil, exposure, low nutrients) (1)\n• They begin to break down rock (weathering), trap organic matter, and form soil — changing the environment and making it suitable for later successional species (1)` },
      { q: 'Explain why deflected succession occurs and give an example.', marks: 3, markScheme: `• Deflected succession (plagioclimax) occurs when human activity or other factors prevent the natural climax community from developing (1)\n• The community is maintained at a sub-climax stage by continued management (1)\n• Example: heathland maintained by grazing/burning — without management it would succeed to woodland (the natural climax for that climate) (1)` },
      { q: 'Explain what is meant by "sustainable development" in the context of managing ecosystems.', marks: 3, markScheme: `• Sustainable development meets the needs of the present without compromising the ability of future generations to meet their own needs (1)\n• In ecosystem management: resources are used at a rate that allows natural replenishment (e.g., sustainable forestry, fishing quotas) (1)\n• It requires balancing economic, social, and environmental considerations — maintaining biodiversity and ecosystem services long-term (1)` },
      { q: 'Explain how ocean acidification affects marine organisms with calcium carbonate shells.', marks: 3, markScheme: `• Increased atmospheric CO₂ dissolves in seawater, forming carbonic acid and lowering ocean pH (1)\n• Lower pH reduces the concentration of carbonate ions (CO₃²⁻) available for organisms to build CaCO₃ shells/skeletons (1)\n• Affected organisms (corals, molluscs, foraminifera) struggle to form/maintain shells, weakening structures and potentially causing population declines — disrupting marine food webs (1)` },
      { q: 'Describe how gene therapy could potentially treat cystic fibrosis.', marks: 4, markScheme: `• Cystic fibrosis is caused by a mutation in the CFTR gene (chloride ion channel) — gene therapy aims to deliver a functional copy (1)\n• A vector (e.g., adenovirus or liposome) carries the normal CFTR gene to lung epithelial cells (1)\n• If successfully expressed, functional CFTR protein would restore normal chloride ion transport and reduce mucus build-up (1)\n• Challenges: short-lived expression (lung cells replaced every few weeks), immune response to vectors, difficulty reaching all affected cells (1)` },
      { q: 'Explain the term "carbon footprint" and describe two ways an individual can reduce theirs.', marks: 3, markScheme: `• Carbon footprint is the total amount of greenhouse gases (expressed as CO₂ equivalent) emitted directly or indirectly by an individual, organisation, or product (1)\n• Reduction methods (any 2): use public transport/cycle instead of driving; reduce meat consumption (lower agricultural emissions); improve home insulation/use renewable energy; buy local food (reduce food miles) (2)` },
      { q: 'Describe the potential benefits of using biofuels as an alternative to fossil fuels.', marks: 3, markScheme: `• Biofuels are produced from biological material (biomass) which absorbed CO₂ during growth — potentially carbon neutral over the growth-burn cycle (1)\n• They are renewable: crops can be regrown, unlike finite fossil fuels (1)\n• They can reduce dependence on imported fossil fuels, improving energy security; and they produce fewer particulates/sulfur emissions (1)` },
      { q: 'Explain one disadvantage of biofuel production.', marks: 2, markScheme: `• Growing biofuel crops requires land that could otherwise be used for food production — potentially increasing food prices and contributing to food insecurity (1)\n• Large-scale monoculture biofuel crops can reduce biodiversity, and energy is needed for production/processing, reducing net carbon benefit (1)` },
      { q: 'Explain the role of international seed banks (e.g., Svalbard Global Seed Vault) in conservation.', marks: 3, markScheme: `• Seed banks store seeds of crop species and wild relatives in controlled conditions (low temperature, low humidity) for long-term preservation (1)\n• They conserve genetic diversity — including rare varieties and wild strains with potentially useful alleles (disease resistance, drought tolerance) (1)\n• If a crop variety is lost in the field (due to disease, climate change, or conflict), it can be re-established from stored seeds — an insurance policy for food security (1)` },
      { q: 'Evaluate the use of GM crops that produce their own insecticide (e.g., Bt crops).', marks: 4, markScheme: `• Advantage: reduces need for chemical pesticide application — saving farmer costs and reducing environmental pollution (1)\n• Advantage: targeted — the Bt toxin kills specific pest insects that eat the crop, potentially sparing non-target organisms more than broad-spectrum sprays (1)\n• Disadvantage: pests may evolve resistance to the Bt toxin over time, reducing long-term effectiveness (1)\n• Disadvantage: concerns about effects on non-target organisms (e.g., monarch butterfly larvae feeding on Bt pollen-dusted milkweed) and gene flow to wild relatives (1)` },
      { q: 'Describe the use of biological indicators to assess pollution levels in a river.', marks: 3, markScheme: `• Certain species are sensitive or tolerant to pollution levels — their presence/absence indicates water quality (1)\n• High oxygen/clean water indicators: mayfly nymphs, stonefly nymphs, freshwater shrimp (1)\n• Low oxygen/polluted water indicators: rat-tailed maggots, bloodworms, Tubifex worms — their presence indicates organic pollution and low dissolved oxygen (1)` },
      { q: 'Explain why genetic engineering is considered more precise than selective breeding.', marks: 3, markScheme: `• Genetic engineering targets a specific known gene and inserts it directly into the organism (1)\n• Selective breeding transfers whole genomes (thousands of genes) and relies on chance recombination — many unwanted traits may be carried along (1)\n• Genetic engineering can transfer genes between unrelated species (overcoming reproductive barriers), achieving outcomes impossible through breeding (1)` },
    ],
  },

};

if (typeof module !== 'undefined') module.exports = BIOLOGY_OCR_B_PRACTICE;
